/**
 * Session slice for Zustand store
 * Matches Go CLI session format for rollback compatibility
 */

import type { StateCreator } from "zustand";
import type { Store, SessionSlice } from "../types.js";

export const createSessionSlice: StateCreator<Store, [], [], SessionSlice> = (
  set,
  get
) => ({
  sessionId: null,
  totalCost: 0,
  tokenCount: {
    input: 0,
    output: 0,
  },
  permissionMode: "default",
  isCompacting: false,

  updateSession: (data): void => {
    set((state) => ({
      sessionId: data.id ?? state.sessionId,
      totalCost: data.cost ?? state.totalCost,
      // Note: Go format uses tool_calls, we track internally as tokenCount
    }));
  },

  incrementCost: (cost): void => {
    set((state) => ({
      totalCost: state.totalCost + cost,
    }));
  },

  addTokens: (tokens): void => {
    set((state) => ({
      tokenCount: {
        input: state.tokenCount.input + (tokens.input ?? 0),
        output: state.tokenCount.output + (tokens.output ?? 0),
      },
    }));
  },

  setPermissionMode: (mode): void => {
    set({ permissionMode: mode });
  },

  setCompacting: (compacting): void => {
    set({ isCompacting: compacting });
  },

  // Computed property: check if currently in plan mode
  isPlanMode: (): boolean => {
    return get().permissionMode === "plan";
  },

  clearSession: (): void => {
    set({
      sessionId: null,
      totalCost: 0,
      tokenCount: {
        input: 0,
        output: 0,
      },
      permissionMode: "default",
      isCompacting: false,
    });
  },
});

/**
 * Zustand store - combines all slices with devtools middleware
 * Central state management for TUI application
 */

import { create } from "zustand";
import { devtools, persist } from "zustand/middleware";
import type { Store } from "./types.js";
import { createMessagesSlice } from "./slices/messages.js";
import { createAgentsSlice } from "./slices/agents.js";
import { createSessionSlice } from "./slices/session.js";
import { createUISlice } from "./slices/ui.js";
import { createInputSlice } from "./slices/input.js";
import { createModalSlice } from "./slices/modal.js";
import { createTelemetrySlice } from "./slices/telemetry.js";

/**
 * Combined Zustand store with all slices
 * Persistence: Only messages, agents, and session slices are persisted
 * UI and input slices are ephemeral (reset on app restart)
 */

// Core store configuration (shared between dev and prod)
const storeConfig = (...a: Parameters<typeof createMessagesSlice>) => ({
  ...createMessagesSlice(...a),
  ...createAgentsSlice(...a),
  ...createSessionSlice(...a),
  ...createUISlice(...a),
  ...createInputSlice(...a),
  ...createModalSlice(...a),
  ...createTelemetrySlice(...a),
});

const persistConfig = {
  name: "tui-store",
  // Only persist messages, agents, and session
  // UI state, input history, and telemetry are ephemeral
  partialize: (state: Store) => ({
    messages: state.messages,
    agents: state.agents,
    selectedAgentId: state.selectedAgentId,
    rootAgentId: state.rootAgentId,
    sessionId: state.sessionId,
    totalCost: state.totalCost,
    tokenCount: state.tokenCount,
    // Exclude: streaming, focusedPanel, inputHistory, inputHistoryIndex, modalQueue
    // Exclude telemetry: routingDecisions, lastHandoff, sharpEdges, totalRoutingCost
  }),
};

// Conditionally apply devtools middleware only in development
// Type assertion needed due to conditional middleware application
// The middleware chain returns a compatible store creator despite TypeScript's inability to infer it
export const useStore = create<Store>()(
  (process.env["NODE_ENV"] === "development"
    ? devtools(persist(storeConfig, persistConfig), { name: "TUI Store" })
    : persist(storeConfig, persistConfig)) as unknown as typeof storeConfig
);

// Export types for convenience
export type { Store } from "./types.js";
export * from "./types.js";

/**
 * Type definitions for Zustand store
 * Central state management for TUI application
 */

// Content block types (matching Anthropic SDK structure)
export interface TextContent {
  type: "text";
  text: string;
}

export interface ToolUseContent {
  type: "tool_use";
  id: string;
  name: string;
  input: Record<string, unknown>;
}

export interface ToolResultContent {
  type: "tool_result";
  tool_use_id: string;
  content: string;
  is_error?: boolean;
}

export type ContentBlock = TextContent | ToolUseContent | ToolResultContent;

// Message interface
export interface Message {
  id: string;
  role: "user" | "assistant" | "system";
  content: ContentBlock[];
  partial: boolean;
  timestamp: number;
}

// Agent interface with tree structure
export interface Agent {
  id: string;
  parentId: string | null;
  model: string;
  tier: "haiku" | "sonnet" | "opus";
  status: "spawning" | "running" | "complete" | "error";
  description?: string;
  startTime: number;
  endTime?: number;
  tokenUsage?: {
    input: number;
    output: number;
  };
}

// Session data (matches Go format exactly)
export interface SessionData {
  id: string;
  name?: string;
  created_at: string; // ISO8601
  last_used: string; // ISO8601
  cost: number;
  tool_calls: number;
}

// Token count structure
export interface TokenCount {
  input: number;
  output: number;
}

// Messages slice
export interface MessagesSlice {
  messages: Message[];
  addMessage: (msg: Omit<Message, "id" | "timestamp">) => void;
  updateLastMessage: (content: ContentBlock[]) => void;
  clearMessages: () => void;
}

// Agents slice
export interface AgentsSlice {
  agents: Record<string, Agent>;
  selectedAgentId: string | null;
  rootAgentId: string | null;
  addAgent: (agent: Omit<Agent, "startTime">) => void;
  updateAgent: (id: string, data: Partial<Agent>) => void;
  selectAgent: (id: string | null) => void;
  getAgentChildren: (id: string) => Agent[];
  clearAgents: () => void;
}

// Session slice (Go format compatible)
export interface SessionSlice {
  sessionId: string | null;
  totalCost: number;
  tokenCount: TokenCount;
  permissionMode: string;
  isCompacting: boolean;
  updateSession: (data: Partial<SessionData>) => void;
  incrementCost: (cost: number) => void;
  addTokens: (tokens: Partial<TokenCount>) => void;
  setPermissionMode: (mode: string) => void;
  setCompacting: (compacting: boolean) => void;
  isPlanMode: () => boolean;
  clearSession: () => void;
}

// UI slice
export interface UISlice {
  streaming: boolean;
  focusedPanel: "claude" | "agents";
  setStreaming: (streaming: boolean) => void;
  setFocusedPanel: (panel: "claude" | "agents") => void;
}

// Input history slice (ephemeral - not persisted)
export interface InputSlice {
  inputHistory: string[]; // Max 100 entries
  inputHistoryIndex: number; // -1 = not navigating, 0+ = position
  addToHistory: (input: string) => void;
  navigateHistory: (direction: "up" | "down") => string | null;
  resetHistoryIndex: () => void;
  clearHistory: () => void;
}

// Modal slice (ephemeral - not persisted)
export interface ModalSlice {
  modalQueue: Array<{
    id: string;
    type: "ask" | "confirm" | "input" | "select";
    payload: unknown;
    resolve: (response: ModalResponse) => void;
    reject: (error: Error) => void;
    timeout?: number;
    timeoutId?: NodeJS.Timeout;
  }>;
  enqueue: <T>(
    request: Omit<
      {
        id: string;
        type: "ask" | "confirm" | "input" | "select";
        payload: T;
        resolve: (response: ModalResponse) => void;
        reject: (error: Error) => void;
        timeout?: number;
        timeoutId?: NodeJS.Timeout;
      },
      "id" | "resolve" | "reject" | "timeoutId"
    >
  ) => Promise<ModalResponse>;
  dequeue: (id: string, response: ModalResponse) => void;
  cancel: (id: string) => void;
}

export type ModalResponse =
  | { type: "ask"; value: string }
  | { type: "confirm"; confirmed: boolean; cancelled: boolean }
  | { type: "input"; value: string }
  | { type: "select"; selected: string; index: number };

// Import telemetry types
import type { TelemetrySlice } from "./slices/telemetry.js";
export type { TelemetrySlice, RoutingDecision, Handoff, SharpEdge } from "./slices/telemetry.js";

// Combined store type
export type Store = MessagesSlice &
  AgentsSlice &
  SessionSlice &
  UISlice &
  InputSlice &
  ModalSlice &
  TelemetrySlice;

/**
 * Agents slice for Zustand store
 * Manages agent tree with parent/child relationships
 */

import type { StateCreator } from "zustand";
import type { Store, AgentsSlice, Agent } from "../types.js";

export const createAgentsSlice: StateCreator<Store, [], [], AgentsSlice> = (
  set,
  get
) => ({
  agents: {},
  selectedAgentId: null,
  rootAgentId: null,

  addAgent: (agent): void => {
    set((state) => {
      const newAgent: Agent = {
        ...agent,
        startTime: Date.now(),
      };

      const agents = { ...state.agents };
      agents[newAgent.id] = newAgent;

      // Track root agent (first agent with no parent)
      const rootAgentId =
        state.rootAgentId || (agent.parentId === null ? newAgent.id : null);

      return {
        agents,
        rootAgentId,
      };
    });
  },

  updateAgent: (id, data): void => {
    set((state) => {
      const agent = state.agents[id];
      if (!agent) {
        return state;
      }

      const agents = { ...state.agents };
      agents[id] = { ...agent, ...data };

      return { agents };
    });
  },

  selectAgent: (id): void => {
    set({ selectedAgentId: id });
  },

  getAgentChildren: (id): Agent[] => {
    const agents = get().agents;

    // Null safety: return empty array if parent doesn't exist
    if (!(id in agents)) {
      return [];
    }

    const children: Agent[] = [];

    Object.values(agents).forEach((agent) => {
      if (agent.parentId === id) {
        children.push(agent);
      }
    });

    return children;
  },

  clearAgents: (): void => {
    set({
      agents: {},
      selectedAgentId: null,
      rootAgentId: null,
    });
  },
});

/**
 * Session file operations hook
 * Manages session persistence with Go-compatible format
 *
 * SESSION FILE FORMAT (CRITICAL - Must Match Go):
 * {
 *   "id": "uuid-here",
 *   "name": "optional-name",
 *   "created_at": "2026-02-01T10:00:00Z",
 *   "last_used": "2026-02-01T11:30:00Z",
 *   "cost": 0.42,
 *   "tool_calls": 127
 * }
 */

import { promises as fs } from "fs";
import { join } from "path";
import { homedir } from "os";
import type { SessionData } from "../store/types.js";

/**
 * Get session directory path
 * Allows override via environment variable for testing
 */
function getSessionDir(): string {
  const home = process.env["HOME"] || homedir();
  return join(home, ".claude", "sessions");
}

/**
 * Ensure session directory exists
 */
async function ensureSessionDir(): Promise<void> {
  const sessionDir = getSessionDir();
  try {
    await fs.mkdir(sessionDir, { recursive: true });
  } catch (error) {
    if ((error as NodeJS.ErrnoException).code !== "EEXIST") {
      throw error;
    }
  }
}

/**
 * List all sessions from ~/.claude/sessions/
 * Sorted by last_used descending (most recent first)
 * Skips invalid JSON files gracefully
 */
export async function listSessions(): Promise<SessionData[]> {
  await ensureSessionDir();
  const sessionDir = getSessionDir();

  try {
    const files = await fs.readdir(sessionDir);
    const sessions: SessionData[] = [];

    for (const file of files) {
      if (!file.endsWith(".json")) continue;

      try {
        const filePath = join(sessionDir, file);
        const content = await fs.readFile(filePath, "utf-8");
        const session = JSON.parse(content) as SessionData;

        // Validate required fields
        if (
          session.id &&
          session.created_at &&
          session.last_used &&
          typeof session.cost === "number" &&
          typeof session.tool_calls === "number"
        ) {
          sessions.push(session);
        }
      } catch (error) {
        // Skip invalid files - don't crash on corrupted JSON
        if (process.env["VERBOSE"]) {
          console.error(`Skipping invalid session file: ${file}`, error);
        }
      }
    }

    // Sort by last_used descending (most recent first)
    sessions.sort((a, b) => {
      return new Date(b.last_used).getTime() - new Date(a.last_used).getTime();
    });

    return sessions;
  } catch (error) {
    if ((error as NodeJS.ErrnoException).code === "ENOENT") {
      return []; // Directory doesn't exist yet
    }
    throw error;
  }
}

/**
 * Load specific session by ID
 * Throws if session doesn't exist or is invalid
 */
export async function loadSession(id: string): Promise<SessionData> {
  const sessionDir = getSessionDir();
  const filePath = join(sessionDir, `${id}.json`);

  try {
    const content = await fs.readFile(filePath, "utf-8");
    const session = JSON.parse(content) as SessionData;

    // Validate required fields
    if (
      !session.id ||
      !session.created_at ||
      !session.last_used ||
      typeof session.cost !== "number" ||
      typeof session.tool_calls !== "number"
    ) {
      throw new Error(`Invalid session format: ${id}`);
    }

    return session;
  } catch (error) {
    if ((error as NodeJS.ErrnoException).code === "ENOENT") {
      throw new Error(`Session not found: ${id}`);
    }
    throw error;
  }
}

/**
 * Save session to file
 * Creates/updates session file with Go-compatible format
 * Uses snake_case field names for Go compatibility
 */
export async function saveSession(session: SessionData): Promise<void> {
  await ensureSessionDir();
  const sessionDir = getSessionDir();
  const filePath = join(sessionDir, `${session.id}.json`);

  // Ensure ISO 8601 format with Z suffix
  const data: SessionData = {
    id: session.id,
    name: session.name,
    created_at: session.created_at,
    last_used: new Date().toISOString(), // Update last_used on save
    cost: session.cost,
    tool_calls: session.tool_calls,
  };

  await fs.writeFile(filePath, JSON.stringify(data, null, 2), "utf-8");
}

/**
 * Delete session file
 */
export async function deleteSession(id: string): Promise<void> {
  const sessionDir = getSessionDir();
  const filePath = join(sessionDir, `${id}.json`);

  try {
    await fs.unlink(filePath);
  } catch (error) {
    if ((error as NodeJS.ErrnoException).code === "ENOENT") {
      throw new Error(`Session not found: ${id}`);
    }
    throw error;
  }
}

/**
 * React hook for session operations
 * Provides session CRUD operations with error handling
 */
export function useSession() {
  return {
    listSessions,
    loadSession,
    saveSession,
    deleteSession,
  };
}

