/**
 * Session file operations hook
 * Manages session persistence with Go-compatible format
 *
 * SESSION FILE FORMAT (CRITICAL - Must Match Go):
 * {
 *   "id": "uuid-here",
 *   "name": "optional-name",
 *   "created_at": "2026-02-01T10:00:00Z",
 *   "last_used": "2026-02-01T11:30:00Z",
 *   "cost": 0.42,
 *   "tool_calls": 127
 * }
 */

import { promises as fs } from "fs";
import { join } from "path";
import { homedir } from "os";
import type { SessionData } from "../store/types.js";

/**
 * Get session directory path
 * Allows override via environment variable for testing
 */
function getSessionDir(): string {
  const home = process.env["HOME"] || homedir();
  return join(home, ".claude", "sessions");
}

/**
 * Ensure session directory exists
 */
async function ensureSessionDir(): Promise<void> {
  const sessionDir = getSessionDir();
  try {
    await fs.mkdir(sessionDir, { recursive: true });
  } catch (error) {
    if ((error as NodeJS.ErrnoException).code !== "EEXIST") {
      throw error;
    }
  }
}

/**
 * List all sessions from ~/.claude/sessions/
 * Sorted by last_used descending (most recent first)
 * Skips invalid JSON files gracefully
 */
export async function listSessions(): Promise<SessionData[]> {
  await ensureSessionDir();
  const sessionDir = getSessionDir();

  try {
    const files = await fs.readdir(sessionDir);
    const sessions: SessionData[] = [];

    for (const file of files) {
      if (!file.endsWith(".json")) continue;

      try {
        const filePath = join(sessionDir, file);
        const content = await fs.readFile(filePath, "utf-8");
        const session = JSON.parse(content) as SessionData;

        // Validate required fields
        if (
          session.id &&
          session.created_at &&
          session.last_used &&
          typeof session.cost === "number" &&
          typeof session.tool_calls === "number"
        ) {
          sessions.push(session);
        }
      } catch (error) {
        // Skip invalid files - don't crash on corrupted JSON
        if (process.env["VERBOSE"]) {
          console.error(`Skipping invalid session file: ${file}`, error);
        }
      }
    }

    // Sort by last_used descending (most recent first)
    sessions.sort((a, b) => {
      return new Date(b.last_used).getTime() - new Date(a.last_used).getTime();
    });

    return sessions;
  } catch (error) {
    if ((error as NodeJS.ErrnoException).code === "ENOENT") {
      return []; // Directory doesn't exist yet
    }
    throw error;
  }
}

/**
 * Load specific session by ID
 * Throws if session doesn't exist or is invalid
 */
export async function loadSession(id: string): Promise<SessionData> {
  const sessionDir = getSessionDir();
  const filePath = join(sessionDir, `${id}.json`);

  try {
    const content = await fs.readFile(filePath, "utf-8");
    const session = JSON.parse(content) as SessionData;

    // Validate required fields
    if (
      !session.id ||
      !session.created_at ||
      !session.last_used ||
      typeof session.cost !== "number" ||
      typeof session.tool_calls !== "number"
    ) {
      throw new Error(`Invalid session format: ${id}`);
    }

    return session;
  } catch (error) {
    if ((error as NodeJS.ErrnoException).code === "ENOENT") {
      throw new Error(`Session not found: ${id}`);
    }
    throw error;
  }
}

/**
 * Save session to file
 * Creates/updates session file with Go-compatible format
 * Uses snake_case field names for Go compatibility
 */
export async function saveSession(session: SessionData): Promise<void> {
  await ensureSessionDir();
  const sessionDir = getSessionDir();
  const filePath = join(sessionDir, `${session.id}.json`);

  // Ensure ISO 8601 format with Z suffix
  const data: SessionData = {
    id: session.id,
    name: session.name,
    created_at: session.created_at,
    last_used: new Date().toISOString(), // Update last_used on save
    cost: session.cost,
    tool_calls: session.tool_calls,
  };

  await fs.writeFile(filePath, JSON.stringify(data, null, 2), "utf-8");
}

/**
 * Delete session file
 */
export async function deleteSession(id: string): Promise<void> {
  const sessionDir = getSessionDir();
  const filePath = join(sessionDir, `${id}.json`);

  try {
    await fs.unlink(filePath);
  } catch (error) {
    if ((error as NodeJS.ErrnoException).code === "ENOENT") {
      throw new Error(`Session not found: ${id}`);
    }
    throw error;
  }
}

/**
 * React hook for session operations
 * Provides session CRUD operations with error handling
 */
export function useSession() {
  return {
    listSessions,
    loadSession,
    saveSession,
    deleteSession,
  };
}

import React, { useState, useEffect } from "react";
import { Box, Text, useInput } from "ink";
import { colors } from "./config/theme.js";
import { Layout } from "./components/Layout.js";
import { LayoutSpike } from "./components/LayoutSpike.js";
import { ResponsiveLayout } from "./components/ResponsiveLayout.js";
import { BorderStyleTest } from "./components/BorderStyleTest.js";
import { loadSession, saveSession } from "./hooks/useSession.js";
import { useStore } from "./store/index.js";
import { nanoid } from "nanoid";

type DemoMode = "main" | "hello" | "layout" | "responsive" | "borders";

interface AppProps {
  sessionId?: string;
  verbose?: boolean;
}

/**
 * Root component for GOfortress TUI
 * Entry point for the application UI structure
 * Includes spike testing modes for layout validation
 * Handles session persistence and resumption
 */
export function App({ sessionId, verbose }: AppProps): JSX.Element {
  const [mode, setMode] = useState<DemoMode>("main");
  const [loading, setLoading] = useState(!!sessionId);
  const updateSession = useStore((state) => state.updateSession);
  const totalCost = useStore((state) => state.totalCost);
  const currentSessionId = useStore((state) => state.sessionId);

  // Set verbose mode
  useEffect(() => {
    if (verbose) {
      process.env["VERBOSE"] = "1";
    }
  }, [verbose]);

  // Load session on mount if sessionId provided
  useEffect(() => {
    async function resumeSession() {
      if (!sessionId) return;

      try {
        const session = await loadSession(sessionId);
        updateSession({
          id: session.id,
          cost: session.cost,
        });

        if (verbose) {
          console.log(`[Session] Resumed: ${session.id}`);
          console.log(`[Session] Cost: $${session.cost.toFixed(4)}`);
          console.log(`[Session] Tools: ${session.tool_calls}`);
        }
      } catch (error) {
        console.error(`Failed to load session: ${sessionId}`, error);
        // Continue with new session on error
        updateSession({ id: nanoid() });
      } finally {
        setLoading(false);
      }
    }

    resumeSession();
  }, [sessionId, updateSession, verbose]);

  // Auto-save session on cost changes
  useEffect(() => {
    async function persistSession() {
      if (!currentSessionId) return;
      if (totalCost === 0) return; // Don't save empty sessions

      try {
        const tokenCount = useStore.getState().tokenCount;
        const toolCalls = tokenCount.input + tokenCount.output; // Approximate tool calls

        await saveSession({
          id: currentSessionId,
          created_at: new Date().toISOString(),
          last_used: new Date().toISOString(),
          cost: totalCost,
          tool_calls: toolCalls,
        });

        if (verbose) {
          console.log(`[Session] Saved: ${currentSessionId}`);
        }
      } catch (error) {
        console.error("Failed to save session:", error);
      }
    }

    persistSession();
  }, [totalCost, currentSessionId, verbose]);

  // Show loading state while resuming session
  if (loading) {
    return (
      <Box padding={1}>
        <Text color={colors.muted}>Loading session {sessionId}...</Text>
      </Box>
    );
  }

  useInput((input, _key) => {
    // Cycle through demo modes with number keys
    if (input === "0") setMode("main");
    if (input === "1") setMode("hello");
    if (input === "2") setMode("layout");
    if (input === "3") setMode("responsive");
    if (input === "4") setMode("borders");

    // Exit handled by Layout component (Escape) or Ink's default Ctrl+C
  });

  return (
    <Box flexDirection="column" width="100%" height="100%">
      {mode === "main" ? (
        // Main application layout (TUI-007)
        <Layout />
      ) : (
        // Spike testing modes
        <>
          {/* Header */}
          <Box borderStyle="round" borderColor={colors.primary} paddingX={2}>
            <Text bold color={colors.primary}>
              GOfortress TUI - Ink Layout Spike
            </Text>
          </Box>

          {/* Mode selector */}
          <Box paddingX={2} paddingY={1}>
            <Text dimColor color={colors.muted}>
              Press: [0] Main | [1] Hello | [2] Layout | [3] Responsive | [4] Borders | [Ctrl+C] Exit
            </Text>
          </Box>

          {/* Content area */}
          <Box flexGrow={1}>
            {mode === "hello" && (
              <Box flexDirection="column" padding={1}>
                <Text bold color={colors.primary}>
                  GOfortress TUI
                </Text>
                <Text color={colors.muted}>Hello from Ink!</Text>
                <Box marginTop={1}>
                  <Text color={colors.secondary}>
                    Use number keys to test different spike components
                  </Text>
                </Box>
              </Box>
            )}

            {mode === "layout" && <LayoutSpike />}
            {mode === "responsive" && <ResponsiveLayout />}
            {mode === "borders" && <BorderStyleTest />}
          </Box>
        </>
      )}
    </Box>
  );
}

