import React, { useState, useEffect } from "react";
import { Box, Text, useInput } from "ink";
import { colors } from "./config/theme.js";
import { Layout } from "./components/Layout.js";
import { LayoutSpike } from "./components/LayoutSpike.js";
import { ResponsiveLayout } from "./components/ResponsiveLayout.js";
import { BorderStyleTest } from "./components/BorderStyleTest.js";
import { loadSession, saveSession } from "./hooks/useSession.js";
import { useStore } from "./store/index.js";
import { nanoid } from "nanoid";

type DemoMode = "main" | "hello" | "layout" | "responsive" | "borders";

interface AppProps {
  sessionId?: string;
  verbose?: boolean;
}

/**
 * Root component for GOfortress TUI
 * Entry point for the application UI structure
 * Includes spike testing modes for layout validation
 * Handles session persistence and resumption
 */
export function App({ sessionId, verbose }: AppProps): JSX.Element {
  const [mode, setMode] = useState<DemoMode>("main");
  const [loading, setLoading] = useState(!!sessionId);
  const updateSession = useStore((state) => state.updateSession);
  const totalCost = useStore((state) => state.totalCost);
  const currentSessionId = useStore((state) => state.sessionId);

  // Set verbose mode
  useEffect(() => {
    if (verbose) {
      process.env["VERBOSE"] = "1";
    }
  }, [verbose]);

  // Load session on mount if sessionId provided
  useEffect(() => {
    async function resumeSession() {
      if (!sessionId) return;

      try {
        const session = await loadSession(sessionId);
        updateSession({
          id: session.id,
          cost: session.cost,
        });

        if (verbose) {
          console.log(`[Session] Resumed: ${session.id}`);
          console.log(`[Session] Cost: $${session.cost.toFixed(4)}`);
          console.log(`[Session] Tools: ${session.tool_calls}`);
        }
      } catch (error) {
        console.error(`Failed to load session: ${sessionId}`, error);
        // Continue with new session on error
        updateSession({ id: nanoid() });
      } finally {
        setLoading(false);
      }
    }

    resumeSession();
  }, [sessionId, updateSession, verbose]);

  // Auto-save session on cost changes
  useEffect(() => {
    async function persistSession() {
      if (!currentSessionId) return;
      if (totalCost === 0) return; // Don't save empty sessions

      try {
        const tokenCount = useStore.getState().tokenCount;
        const toolCalls = tokenCount.input + tokenCount.output; // Approximate tool calls

        await saveSession({
          id: currentSessionId,
          created_at: new Date().toISOString(),
          last_used: new Date().toISOString(),
          cost: totalCost,
          tool_calls: toolCalls,
        });

        if (verbose) {
          console.log(`[Session] Saved: ${currentSessionId}`);
        }
      } catch (error) {
        console.error("Failed to save session:", error);
      }
    }

    persistSession();
  }, [totalCost, currentSessionId, verbose]);

  // Show loading state while resuming session
  if (loading) {
    return (
      <Box padding={1}>
        <Text color={colors.muted}>Loading session {sessionId}...</Text>
      </Box>
    );
  }

  useInput((input, _key) => {
    // Cycle through demo modes with number keys
    if (input === "0") setMode("main");
    if (input === "1") setMode("hello");
    if (input === "2") setMode("layout");
    if (input === "3") setMode("responsive");
    if (input === "4") setMode("borders");

    // Exit handled by Layout component (Escape) or Ink's default Ctrl+C
  });

  return (
    <Box flexDirection="column" width="100%" height="100%">
      {mode === "main" ? (
        // Main application layout (TUI-007)
        <Layout />
      ) : (
        // Spike testing modes
        <>
          {/* Header */}
          <Box borderStyle="round" borderColor={colors.primary} paddingX={2}>
            <Text bold color={colors.primary}>
              GOfortress TUI - Ink Layout Spike
            </Text>
          </Box>

          {/* Mode selector */}
          <Box paddingX={2} paddingY={1}>
            <Text dimColor color={colors.muted}>
              Press: [0] Main | [1] Hello | [2] Layout | [3] Responsive | [4] Borders | [Ctrl+C] Exit
            </Text>
          </Box>

          {/* Content area */}
          <Box flexGrow={1}>
            {mode === "hello" && (
              <Box flexDirection="column" padding={1}>
                <Text bold color={colors.primary}>
                  GOfortress TUI
                </Text>
                <Text color={colors.muted}>Hello from Ink!</Text>
                <Box marginTop={1}>
                  <Text color={colors.secondary}>
                    Use number keys to test different spike components
                  </Text>
                </Box>
              </Box>
            )}

            {mode === "layout" && <LayoutSpike />}
            {mode === "responsive" && <ResponsiveLayout />}
            {mode === "borders" && <BorderStyleTest />}
          </Box>
        </>
      )}
    </Box>
  );
}

/**
 * Zustand store - combines all slices with devtools middleware
 * Central state management for TUI application
 */

import { create } from "zustand";
import { devtools, persist } from "zustand/middleware";
import type { Store } from "./types.js";
import { createMessagesSlice } from "./slices/messages.js";
import { createAgentsSlice } from "./slices/agents.js";
import { createSessionSlice } from "./slices/session.js";
import { createUISlice } from "./slices/ui.js";
import { createInputSlice } from "./slices/input.js";
import { createModalSlice } from "./slices/modal.js";
import { createTelemetrySlice } from "./slices/telemetry.js";

/**
 * Combined Zustand store with all slices
 * Persistence: Only messages, agents, and session slices are persisted
 * UI and input slices are ephemeral (reset on app restart)
 */

// Core store configuration (shared between dev and prod)
const storeConfig = (...a: Parameters<typeof createMessagesSlice>) => ({
  ...createMessagesSlice(...a),
  ...createAgentsSlice(...a),
  ...createSessionSlice(...a),
  ...createUISlice(...a),
  ...createInputSlice(...a),
  ...createModalSlice(...a),
  ...createTelemetrySlice(...a),
});

const persistConfig = {
  name: "tui-store",
  // Only persist messages, agents, and session
  // UI state, input history, and telemetry are ephemeral
  partialize: (state: Store) => ({
    messages: state.messages,
    agents: state.agents,
    selectedAgentId: state.selectedAgentId,
    rootAgentId: state.rootAgentId,
    sessionId: state.sessionId,
    totalCost: state.totalCost,
    tokenCount: state.tokenCount,
    // Exclude: streaming, focusedPanel, inputHistory, inputHistoryIndex, modalQueue
    // Exclude telemetry: routingDecisions, lastHandoff, sharpEdges, totalRoutingCost
  }),
};

// Conditionally apply devtools middleware only in development
// Type assertion needed due to conditional middleware application
// The middleware chain returns a compatible store creator despite TypeScript's inability to infer it
export const useStore = create<Store>()(
  (process.env["NODE_ENV"] === "development"
    ? devtools(persist(storeConfig, persistConfig), { name: "TUI Store" })
    : persist(storeConfig, persistConfig)) as unknown as typeof storeConfig
);

// Export types for convenience
export type { Store } from "./types.js";
export * from "./types.js";

/**
 * Modal slice for Zustand store
 * Implements Promise-based modal queue with FIFO ordering
 */

import type { StateCreator } from "zustand";
import type { Store } from "../types.js";
import { nanoid } from "nanoid";

// Payload types for different modal variants
export interface AskPayload {
  message: string;
  options?: Array<{ label: string; value: string }>;
  defaultValue?: string;
}

export interface ConfirmPayload {
  action: string;
  destructive?: boolean;
}

export interface InputPayload {
  prompt: string;
  placeholder?: string;
}

export interface SelectPayload {
  message: string;
  options: Array<{ label: string; value: string }>;
}

// Discriminated union for modal responses
export type ModalResponse =
  | { type: "ask"; value: string }
  | { type: "confirm"; confirmed: boolean; cancelled: boolean }
  | { type: "input"; value: string }
  | { type: "select"; selected: string; index: number };

// Internal request structure with Promise handlers
export interface ModalRequest<T = unknown> {
  id: string;
  type: "ask" | "confirm" | "input" | "select";
  payload: T;
  resolve: (response: ModalResponse) => void;
  reject: (error: Error) => void;
  timeout?: number;
  timeoutId?: NodeJS.Timeout;
}

// Public API for enqueuing modals (omits internal fields)
export type EnqueueRequest<T = unknown> = Omit<
  ModalRequest<T>,
  "id" | "resolve" | "reject" | "timeoutId"
>;

// Modal slice interface
export interface ModalSlice {
  modalQueue: ModalRequest[];
  enqueue: <T>(request: EnqueueRequest<T>) => Promise<ModalResponse>;
  dequeue: (id: string, response: ModalResponse) => void;
  cancel: (id: string) => void;
}

export const createModalSlice: StateCreator<Store, [], [], ModalSlice> = (
  set,
  get
) => ({
  modalQueue: [],

  enqueue: <T>(request: EnqueueRequest<T>): Promise<ModalResponse> => {
    return new Promise<ModalResponse>((resolve, reject) => {
      const id = nanoid();
      let timeoutId: NodeJS.Timeout | undefined;
      let completed = false;

      const cleanup = (): void => {
        if (timeoutId) {
          clearTimeout(timeoutId);
        }
      };

      // Wrapped resolve/reject that prevent double-resolution
      const wrappedResolve = (response: ModalResponse): void => {
        if (completed) return;
        completed = true;
        cleanup();
        resolve(response);
      };

      const wrappedReject = (error: Error): void => {
        if (completed) return;
        completed = true;
        cleanup();
        reject(error);
      };

      // Set up optional timeout
      if (request.timeout && request.timeout > 0) {
        timeoutId = setTimeout(() => {
          // Remove from queue
          set((state) => ({
            modalQueue: state.modalQueue.filter((req) => req.id !== id),
          }));

          // Return default or cancel based on modal type
          if (request.type === "confirm") {
            // Confirm modals default to "not confirmed" on timeout
            wrappedResolve({ type: "confirm", confirmed: false, cancelled: true });
          } else if (request.type === "ask" && (request.payload as AskPayload).defaultValue) {
            // Ask modals return default value if provided
            const payload = request.payload as AskPayload;
            wrappedResolve({ type: "ask", value: payload.defaultValue! });
          } else {
            // Other modals reject on timeout
            wrappedReject(new Error(`Modal timeout after ${request.timeout}ms`));
          }
        }, request.timeout);
      }

      const fullRequest: ModalRequest<T> = {
        ...request,
        id,
        resolve: wrappedResolve,
        reject: wrappedReject,
        timeoutId,
      };

      // Add to queue (FIFO)
      set((state) => ({
        modalQueue: [...state.modalQueue, fullRequest],
      }));
    });
  },

  dequeue: (id: string, response: ModalResponse): void => {
    const queue = get().modalQueue;
    const request = queue.find((req) => req.id === id);

    if (!request) {
      return;
    }

    // Clear timeout if exists
    if (request.timeoutId) {
      clearTimeout(request.timeoutId);
    }

    // Remove from queue
    set((state) => ({
      modalQueue: state.modalQueue.filter((req) => req.id !== id),
    }));

    // Resolve the Promise
    request.resolve(response);
  },

  cancel: (id: string): void => {
    const queue = get().modalQueue;
    const request = queue.find((req) => req.id === id);

    if (!request) {
      return;
    }

    // Clear timeout if exists
    if (request.timeoutId) {
      clearTimeout(request.timeoutId);
    }

    // Remove from queue
    set((state) => ({
      modalQueue: state.modalQueue.filter((req) => req.id !== id),
    }));

    // Reject the Promise
    request.reject(new Error("Modal cancelled by user"));
  },
});

import React from "react";
import { Box, useStdout } from "ink";
import { useStore } from "../store/index.js";
import { useKeymap, KeyBinding } from "../hooks/useKeymap.js";
import { useAgentTree } from "../hooks/useAgentTree.js";
import { createGlobalBindings } from "../config/keybindings.js";
import { Banner } from "./Banner.js";
import { ClaudePanel } from "./ClaudePanel.js";
import { AgentTree } from "./AgentTree.js";
import { AgentDetail } from "./AgentDetail.js";
import { ModalOverlay } from "./Modal.js";
import { colors, borders } from "../config/theme.js";

// Fixed heights
const BANNER_HEIGHT = 3; // Banner takes 3 rows

/**
 * Layout component - main 2-panel split (70/30) with focus management
 *
 * Features:
 * - Left panel (70%): Claude conversation
 * - Right panel (30%): Agent tree (60%) + Agent detail (40%)
 * - Global keyboard bindings (Tab, Escape, Ctrl+C, Ctrl+L)
 * - Focus indicated by border color (cyan/gray from theme)
 * - Modal overlay renders when queue is non-empty
 * - Modal captures all input when active
 */
export function Layout(): JSX.Element {
  const { focusedPanel, setFocusedPanel, modalQueue, clearMessages } = useStore();
  const { selectPrevious, selectNext } = useAgentTree();
  const { stdout } = useStdout();

  // Calculate available height for content area
  const terminalHeight = stdout?.rows ?? 24;
  const contentHeight = terminalHeight - BANNER_HEIGHT;

  // Global key bindings (only active when no modal is present)
  const globalBindings = createGlobalBindings({
    toggleFocus: () => {
      setFocusedPanel(focusedPanel === "claude" ? "agents" : "claude");
    },
    handleEscape: () => {
      // If modal is active, cancel it; otherwise exit
      if (modalQueue.length > 0 && modalQueue[0]) {
        const modal = modalQueue[0];
        useStore.getState().cancel(modal.id);
      } else {
        process.exit(0);
      }
    },
    forceQuit: () => {
      process.exit(0);
    },
    clearScreen: () => {
      clearMessages();
    },
  });

  // Agent tree navigation bindings (only when agents panel focused)
  const agentBindings: KeyBinding[] = [
    { key: "up", action: selectPrevious, description: "Select previous agent" },
    { key: "down", action: selectNext, description: "Select next agent" },
  ];

  // Only enable global bindings when no modal is active
  useKeymap(globalBindings, modalQueue.length === 0);

  // Only enable agent navigation when agents panel focused and no modal
  useKeymap(agentBindings, focusedPanel === "agents" && modalQueue.length === 0);

  // Calculate right panel heights (fixed row counts)
  const agentTreeHeight = Math.floor(contentHeight * 0.6);
  const agentDetailHeight = contentHeight - agentTreeHeight;

  return (
    <Box flexDirection="column" height={terminalHeight}>
      {/* Banner - FIXED at top */}
      <Box height={BANNER_HEIGHT}>
        <Banner />
      </Box>

      {/* Content area - FIXED height */}
      <Box flexDirection="row" height={contentHeight}>
        {/* Left Panel: Claude conversation (70%) */}
        <Box width="70%" height={contentHeight}>
          <ClaudePanel focused={focusedPanel === "claude"} maxHeight={contentHeight - 2} />
        </Box>

        {/* Right Panel: Agent tree + detail (30%) */}
        <Box width="30%" flexDirection="column" height={contentHeight}>
          {/* Agent Tree (60% of right panel) */}
          <Box
            height={agentTreeHeight}
            borderStyle={borders.panel}
            borderColor={focusedPanel === "agents" ? colors.focused : colors.unfocused}
            flexDirection="column"
          >
            <AgentTree focused={focusedPanel === "agents"} />
          </Box>

          {/* Agent Detail (40% of right panel) */}
          <Box
            height={agentDetailHeight}
            borderStyle={borders.panel}
            borderColor={colors.muted}
            flexDirection="column"
          >
            <AgentDetail focused={false} />
          </Box>
        </Box>
      </Box>

      {/* Modal overlay (rendered when queue is non-empty) */}
      {modalQueue.length > 0 && modalQueue[0] && <ModalOverlay request={modalQueue[0]} />}
    </Box>
  );
}

/**
 * Modal overlay component - renders centered over content
 * Handles keyboard input (Escape to cancel) and delegates to specific modal types
 */

import React, { Component, ErrorInfo, ReactNode } from "react";
import { Box, Text, useInput } from "ink";
import { useStore } from "../store/index.js";
import type {
  ModalRequest,
  ModalResponse,
  AskPayload,
  ConfirmPayload,
  InputPayload,
  SelectPayload,
} from "../store/slices/modal.js";
import { colors, borders } from "../config/theme.js";
import { AskModal } from "./modals/AskModal.js";
import { ConfirmModal } from "./modals/ConfirmModal.js";
import { InputModal } from "./modals/InputModal.js";
import { SelectModal } from "./modals/SelectModal.js";

interface ModalOverlayProps {
  request: ModalRequest;
}

interface ErrorBoundaryProps {
  children: ReactNode;
  onDismiss: () => void;
}

interface ErrorBoundaryState {
  hasError: boolean;
  error: Error | null;
}

/**
 * Error boundary for modal rendering - catches errors to prevent app crash
 * Displays error message and allows dismissal with Escape key
 */
class ModalErrorBoundary extends Component<ErrorBoundaryProps, ErrorBoundaryState> {
  override state: ErrorBoundaryState = { hasError: false, error: null };

  static getDerivedStateFromError(error: Error): Partial<ErrorBoundaryState> {
    return { hasError: true, error };
  }

  override componentDidCatch(error: Error, info: ErrorInfo): void {
    console.error("[Modal Error]", error, info.componentStack);
  }

  override render(): ReactNode {
    if (this.state.hasError) {
      return <ErrorFallback error={this.state.error} onDismiss={this.props.onDismiss} />;
    }
    return this.props.children;
  }
}

/**
 * Error fallback UI - allows dismissal with Escape
 */
function ErrorFallback({ error, onDismiss }: { error: Error | null; onDismiss: () => void }): JSX.Element {
  useInput((input, key) => {
    if (key.escape) {
      onDismiss();
    }
  });

  return (
    <Box flexDirection="column" padding={1}>
      <Text color="red">Modal Error: {error?.message ?? "Unknown error"}</Text>
      <Text dimColor>Press Escape to dismiss</Text>
    </Box>
  );
}

/**
 * Routes to the appropriate modal component based on request type
 */
function CurrentModal({
  request,
  onComplete,
}: {
  request: ModalRequest;
  onComplete: (response: ModalResponse) => void;
}): JSX.Element {
  switch (request.type) {
    case "ask":
      return <AskModal request={request as ModalRequest<AskPayload>} onComplete={onComplete} />;
    case "confirm":
      return <ConfirmModal request={request as ModalRequest<ConfirmPayload>} onComplete={onComplete} />;
    case "input":
      return <InputModal request={request as ModalRequest<InputPayload>} onComplete={onComplete} />;
    case "select":
      return <SelectModal request={request as ModalRequest<SelectPayload>} onComplete={onComplete} />;
    default:
      return <Box>Unknown modal type</Box>;
  }
}

/**
 * ModalOverlay renders a centered modal over the main content
 * - Captures keyboard focus
 * - Escape cancels modal
 * - Delegates to specific modal type for rendering and Enter handling
 * - Error boundary prevents modal crashes from affecting app
 */
export function ModalOverlay({ request }: ModalOverlayProps): JSX.Element {
  const { dequeue, cancel } = useStore();

  useInput((input, key) => {
    if (key.escape) {
      cancel(request.id);
    }
  });

  return (
    <Box
      position="absolute"
      width="100%"
      height="100%"
      justifyContent="center"
      alignItems="center"
    >
      <Box
        borderStyle={borders.modal}
        borderColor={colors.warning}
        padding={2}
        flexDirection="column"
        // Solid background to make modal opaque (not see-through)
        // @ts-expect-error - Ink supports backgroundColor but types may not include it
        backgroundColor="black"
      >
        <ModalErrorBoundary onDismiss={() => cancel(request.id)}>
          <CurrentModal
            request={request}
            onComplete={(response) => dequeue(request.id, response)}
          />
        </ModalErrorBoundary>
      </Box>
    </Box>
  );
}

/**
 * AskModal component - displays question with optional button options
 * - If options provided: arrow key navigation, Enter selects
 * - If no options: free text input using TextInput primitive, Enter submits
 */

import React, { useState } from "react";
import { Box, Text, useInput } from "ink";
import type { ModalRequest, ModalResponse, AskPayload } from "../../store/slices/modal.js";
import { colors } from "../../config/theme.js";
import { TextInput } from "../primitives/TextInput.js";

interface AskModalProps {
  request: ModalRequest<AskPayload>;
  onComplete: (response: ModalResponse) => void;
}

export function AskModal({ request, onComplete }: AskModalProps): JSX.Element {
  const payload = request.payload as AskPayload;
  const [selectedIndex, setSelectedIndex] = useState(0);
  const [inputValue, setInputValue] = useState(payload.defaultValue || "");

  const hasOptions = payload.options && payload.options.length > 0;

  // Only use useInput for arrow navigation when options are present
  useInput(
    (input, key) => {
      if (hasOptions) {
        // Arrow navigation mode
        if (key.upArrow) {
          setSelectedIndex((prev) =>
            prev > 0 ? prev - 1 : (payload.options?.length || 1) - 1
          );
        } else if (key.downArrow) {
          setSelectedIndex((prev) =>
            prev < (payload.options?.length || 1) - 1 ? prev + 1 : 0
          );
        } else if (key.return) {
          // Return the value field, not the label
          const value = payload.options?.[selectedIndex]?.value || "";
          onComplete({ type: "ask", value });
        }
      }
    },
    { isActive: hasOptions }
  );

  const handleSubmit = () => {
    onComplete({ type: "ask", value: inputValue });
  };

  return (
    <Box flexDirection="column" gap={1}>
      <Text>{payload.message}</Text>

      {hasOptions ? (
        <Box flexDirection="column" marginTop={1}>
          {payload.options?.map((option, index) => (
            <Box key={index}>
              <Text color={index === selectedIndex ? colors.primary : colors.muted}>
                {index === selectedIndex ? "▶ " : "  "}
                {option.label}
              </Text>
            </Box>
          ))}
        </Box>
      ) : (
        <Box marginTop={1}>
          <TextInput
            value={inputValue}
            onChange={setInputValue}
            onSubmit={handleSubmit}
            placeholder="Type your answer..."
            focused={true}
          />
        </Box>
      )}

      <Box marginTop={1}>
        <Text dimColor>
          {hasOptions ? "↑↓ Navigate • Enter Select" : "Enter Submit"} • Esc Cancel
        </Text>
      </Box>
    </Box>
  );
}

