/**
 * MCP server with interactive tools
 * Bridges Claude API calls to TUI modal queue system
 */

import { createSdkMcpServer } from "@anthropic-ai/claude-agent-sdk";
import { askUserTool } from "./tools/askUser.js";
import { confirmActionTool } from "./tools/confirmAction.js";
import { requestInputTool } from "./tools/requestInput.js";
import { selectOptionTool } from "./tools/selectOption.js";
import { testMcpPingTool } from "./tools/testMcpPing.js";
import { spawnAgent } from "./tools/spawnAgent.js";

/**
 * Check if MCP spawning is enabled via feature flag.
 * Defaults to enabled unless explicitly set to "false".
 */
export function isSpawnEnabled(): boolean {
  return process.env.GOGENT_MCP_SPAWN_ENABLED !== "false";
}

/**
 * Get all tools that should be registered based on feature flags.
 * Exported for testing.
 */
export function getServerTools() {
  const tools = [
    // Interactive tools
    askUserTool,
    confirmActionTool,
    requestInputTool,
    selectOptionTool,
    // Test tool (always available for verification)
    testMcpPingTool,
  ];

  // Conditionally add spawn tools
  if (isSpawnEnabled()) {
    tools.push(spawnAgent);
  }

  return tools;
}

/**
 * Create MCP server with all tools.
 * Conditionally includes spawn tools based on feature flag.
 */
export function createMcpServer() {
  const tools = getServerTools();

  return createSdkMcpServer({
    name: "gofortress-interactive",
    version: "1.0.0",
    tools,
  });
}

/**
 * In-process MCP server instance
 * Provides interactive tools that integrate with the TUI modal queue
 */
export const mcpServer = createMcpServer();

import React from "react";
import { render } from "ink";
import { App } from "./App.js";
import { parseCLI } from "./cli.js";
import { listSessions } from "./hooks/useSession.js";
import { ListSessions } from "./commands/list.jsx";
import { setupSignalHandlers } from "./lifecycle/shutdown.js";
import { getRestartManager } from "./lifecycle/restart.js";
import { validateSpawnEnvironment, formatValidationResult } from "./spawn/validation.js";

/**
 * GOfortress TUI Entry Point
 * Renders the main App component in the terminal with lifecycle management
 */

async function main() {
  // Setup graceful shutdown handlers first
  setupSignalHandlers();

  // Validate spawn environment before starting
  // Errors are logged but don't block startup - allows running with spawn disabled
  try {
    const validationResult = await validateSpawnEnvironment();
    if (!validationResult.ok || validationResult.warnings.length > 0) {
      console.error(formatValidationResult(validationResult));
      if (!validationResult.ok) {
        console.error("\n⚠️  Some spawn features may be unavailable\n");
      }
    }
  } catch (err) {
    console.error("Environment validation error:", err instanceof Error ? err.message : err);
    console.error("⚠️  Continuing with warnings - some features may be unavailable\n");
  }

  const options = parseCLI();
  const restartManager = getRestartManager();

  // Handle --list flag
  if (options.list) {
    const sessions = await listSessions();
    const { waitUntilExit } = render(<ListSessions sessions={sessions} />);
    await waitUntilExit();
    process.exit(0);
  }

  // Handle --legacy flag (fallback to Go TUI)
  if (options.legacy) {
    console.error("Legacy mode: Falling back to Go TUI");
    console.error("Run: claude-tui (Go binary)");
    process.exit(1);
  }

  // Record successful start for backoff reset detection
  restartManager.recordSuccessfulStart();

  // Normal mode: render main app
  render(<App sessionId={options.session} verbose={options.verbose} />);
}

/**
 * Restart wrapper with exponential backoff
 * Catches crashes and retries with increasing delays
 */
async function runWithRestart() {
  const restartManager = getRestartManager();

  while (true) {
    try {
      await main();
      // Normal exit - check if we should reset backoff
      restartManager.checkAndResetIfSuccessful();
      break;
    } catch (error) {
      console.error("\n[Restart] App crashed:", error);

      // Check if we should restart
      if (!restartManager.shouldRestart()) {
        console.error("[Restart] Max restart attempts reached");
        console.error("[Restart] Giving up");
        process.exit(1);
      }

      // Calculate delay and log restart info
      const delay = restartManager.getDelay();
      const state = restartManager.getState();
      console.error(
        `[Restart] Attempt ${state.attempts + 1}/${state.maxAttempts} - waiting ${delay}ms...`
      );

      // Record this attempt
      restartManager.recordAttempt();

      // Wait before restarting
      await new Promise((resolve) => setTimeout(resolve, delay));

      console.error("[Restart] Restarting app...\n");
    }
  }
}

runWithRestart().catch((error) => {
  console.error("Fatal error in restart manager:", error);
  process.exit(1);
});

import { describe, it, expect, beforeEach, afterEach, vi } from "vitest";

describe("MCP Server Registration", () => {
  // Store original env
  let originalEnv: string | undefined;

  beforeEach(() => {
    originalEnv = process.env.GOGENT_MCP_SPAWN_ENABLED;
    // Clear module cache to ensure fresh imports
    vi.resetModules();
  });

  afterEach(() => {
    // Restore original env
    if (originalEnv !== undefined) {
      process.env.GOGENT_MCP_SPAWN_ENABLED = originalEnv;
    } else {
      delete process.env.GOGENT_MCP_SPAWN_ENABLED;
    }
  });

  describe("isSpawnEnabled", () => {
    it("should return true when GOGENT_MCP_SPAWN_ENABLED is not set", async () => {
      delete process.env.GOGENT_MCP_SPAWN_ENABLED;
      const { isSpawnEnabled } = await import("./server.js");
      expect(isSpawnEnabled()).toBe(true);
    });

    it("should return true when GOGENT_MCP_SPAWN_ENABLED is 'true'", async () => {
      process.env.GOGENT_MCP_SPAWN_ENABLED = "true";
      const { isSpawnEnabled } = await import("./server.js");
      expect(isSpawnEnabled()).toBe(true);
    });

    it("should return false when GOGENT_MCP_SPAWN_ENABLED is 'false'", async () => {
      process.env.GOGENT_MCP_SPAWN_ENABLED = "false";
      const { isSpawnEnabled } = await import("./server.js");
      expect(isSpawnEnabled()).toBe(false);
    });
  });

  describe("createMcpServer", () => {
    it("should include spawn_agent when spawn is enabled", async () => {
      delete process.env.GOGENT_MCP_SPAWN_ENABLED;
      const { getServerTools } = await import("./server.js");
      const tools = getServerTools();
      const toolNames = tools.map((t) => t.name);
      expect(toolNames).toContain("spawn_agent");
    });

    it("should exclude spawn_agent when spawn is disabled", async () => {
      process.env.GOGENT_MCP_SPAWN_ENABLED = "false";
      const { getServerTools } = await import("./server.js");
      const tools = getServerTools();
      const toolNames = tools.map((t) => t.name);
      expect(toolNames).not.toContain("spawn_agent");
    });

    it("should always include test_mcp_ping tool", async () => {
      const { getServerTools } = await import("./server.js");
      const tools = getServerTools();
      const toolNames = tools.map((t) => t.name);
      expect(toolNames).toContain("test_mcp_ping");
    });
  });
});

import { tool } from "@anthropic-ai/claude-agent-sdk";
import { z } from "zod";
import { spawn } from "child_process";
import { getProcessRegistry } from "../../spawn/processRegistry";
import { randomUUID } from "crypto";

// Constants
const MAX_BUFFER_SIZE = 10 * 1024 * 1024; // 10MB
const DEFAULT_TIMEOUT = 300000; // 5 minutes
const MAX_NESTING_DEPTH = 10;

/**
 * Result from a spawn_agent invocation
 */
export interface SpawnResult {
  agentId: string;
  agent: string;
  success: boolean;
  output?: string;
  error?: string;
  cost?: number;
  turns?: number;
  duration?: number;
  truncated?: boolean;
}

/**
 * spawn_agent MCP tool - spawns Claude CLI processes for Level 1+ agent spawning.
 */
export const spawnAgent = tool(
  "spawn_agent",
  `Spawn a Claude Code subagent with full tool access via CLI.

Use this tool when you need to spawn a sub-subagent (Level 2+).
The spawned agent runs as an independent CLI process with full tool access.

Example:
  spawn_agent({
    agent: "einstein",
    description: "Theoretical analysis",
    prompt: "AGENT: einstein\\n\\nAnalyze the problem...",
    model: "opus"
  })`,
  {
    agent: z.string().describe("Agent type from agents-index.json (e.g., 'einstein', 'backend-reviewer')"),
    description: z.string().describe("Brief description for logging"),
    prompt: z.string().describe("Full prompt to send to the agent"),
    model: z.enum(["haiku", "sonnet", "opus"]).optional().describe("Model to use (default: from agent config)"),
    timeout: z.number().optional().describe("Timeout in ms (default: 300000)"),
    allowedTools: z.array(z.string()).optional().describe("Restrict available tools"),
    maxBudget: z.number().optional().describe("Max budget in USD"),
  },
  async (args): Promise<{ content: Array<{ type: "text"; text: string }> }> => {
    // === DEPTH VALIDATION ===
    const depthError = validateNestingDepth();
    if (depthError) {
      return {
        content: [{
          type: "text",
          text: JSON.stringify({
            agentId: null,
            agent: args.agent,
            success: false,
            error: depthError,
            errorCode: "E_MAX_DEPTH_EXCEEDED",
          }, null, 2),
        }],
      };
    }
    // === END DEPTH VALIDATION ===

    const agentId = randomUUID();
    const registry = getProcessRegistry();
    const timeout = args.timeout ?? DEFAULT_TIMEOUT;
    const startTime = Date.now();

    // Build CLI arguments
    const cliArgs = buildCliArgs(args);

    return new Promise((resolve) => {
      // Spawn CLI process (NO shell: true)
      const proc = spawn("claude", cliArgs, {
        stdio: ["pipe", "pipe", "pipe"],
        env: {
          ...process.env,
          GOGENT_NESTING_LEVEL: String(getCurrentNestingLevel() + 1),
          GOGENT_PARENT_AGENT: agentId,
          GOGENT_SPAWN_METHOD: "mcp-cli",
        },
      });

      // Register with process registry
      registry.register(agentId, proc, args.agent);

      // Output collection with buffer limit
      let stdout = "";
      let stderr = "";
      let truncated = false;

      proc.stdout.on("data", (chunk: Buffer) => {
        if (!truncated && stdout.length < MAX_BUFFER_SIZE) {
          stdout += chunk.toString();
          if (stdout.length >= MAX_BUFFER_SIZE) {
            truncated = true;
            stdout += "\n[OUTPUT TRUNCATED - exceeded 10MB limit]";
          }
        }
      });

      proc.stderr.on("data", (chunk: Buffer) => {
        // Stderr is typically small, but limit anyway
        if (stderr.length < 1024 * 1024) {
          stderr += chunk.toString();
        }
      });

      // Send prompt via stdin
      proc.stdin.write(args.prompt);
      proc.stdin.end();

      // Timeout handling
      const timer = setTimeout(() => {
        // SIGTERM first
        proc.kill("SIGTERM");

        // SIGKILL after 5s if still running
        setTimeout(() => {
          if (!proc.killed) {
            proc.kill("SIGKILL");
          }
        }, 5000);

        const result: SpawnResult = {
          agentId,
          agent: args.agent,
          success: false,
          error: `Agent timed out after ${timeout}ms`,
          duration: Date.now() - startTime,
          truncated,
        };

        resolve({
          content: [{ type: "text", text: JSON.stringify(result, null, 2) }],
        });
      }, timeout);

      // Process completion
      proc.on("close", (code, signal) => {
        clearTimeout(timer);

        const duration = Date.now() - startTime;
        const parsed = parseCliOutput(stdout);

        const result: SpawnResult = {
          agentId,
          agent: args.agent,
          success: code === 0 && !signal,
          output: parsed.result || stdout,
          error: code !== 0 ? stderr || `Exit code ${code}` : undefined,
          cost: parsed.cost,
          turns: parsed.turns,
          duration,
          truncated,
        };

        resolve({
          content: [{ type: "text", text: JSON.stringify(result, null, 2) }],
        });
      });

      proc.on("error", (err) => {
        clearTimeout(timer);

        const result: SpawnResult = {
          agentId,
          agent: args.agent,
          success: false,
          error: `Spawn error: ${err.message}`,
          duration: Date.now() - startTime,
        };

        resolve({
          content: [{ type: "text", text: JSON.stringify(result, null, 2) }],
        });
      });
    });
  }
);

/**
 * Build CLI arguments for claude command.
 */
export function buildCliArgs(args: {
  model?: string;
  allowedTools?: string[];
  maxBudget?: number;
}): string[] {
  const cliArgs = ["-p", "--output-format", "json"];

  if (args.model) {
    cliArgs.push("--model", args.model);
  }

  // Use delegate mode instead of dangerously-skip-permissions
  cliArgs.push("--permission-mode", "delegate");

  if (args.allowedTools && args.allowedTools.length > 0) {
    cliArgs.push("--allowedTools", args.allowedTools.join(","));
  }

  if (args.maxBudget) {
    cliArgs.push("--max-budget-usd", String(args.maxBudget));
  }

  return cliArgs;
}

/**
 * Parse JSON output from claude CLI.
 */
export function parseCliOutput(stdout: string): {
  result?: string;
  cost?: number;
  turns?: number;
} {
  try {
    const json = JSON.parse(stdout.trim());
    return {
      result: json.result || json.output,
      cost: json.cost_usd || json.total_cost_usd,
      turns: json.num_turns,
    };
  } catch {
    // Not valid JSON, return raw output
    return { result: stdout };
  }
}

/**
 * Get current nesting level from environment.
 */
export function getCurrentNestingLevel(): number {
  const level = process.env.GOGENT_NESTING_LEVEL;
  if (!level) return 0;
  const parsed = parseInt(level, 10);
  return isNaN(parsed) ? 0 : parsed;
}

/**
 * Validate nesting depth before spawning.
 * Returns error message if depth exceeded, null if OK.
 */
export function validateNestingDepth(): string | null {
  const currentLevel = getCurrentNestingLevel();

  if (currentLevel >= MAX_NESTING_DEPTH) {
    return `Maximum nesting depth (${MAX_NESTING_DEPTH}) exceeded. ` +
           `Current level: ${currentLevel}. ` +
           `Cannot spawn sub-agent at this depth.`;
  }

  return null;
}

import { execSync } from "child_process";
import * as fs from "fs/promises";
import * as path from "path";
import * as os from "os";

export interface ValidationResult {
  ok: boolean;
  errors: ValidationError[];
  warnings: ValidationWarning[];
}

export interface ValidationError {
  code: string;
  message: string;
  resolution: string;
}

export interface ValidationWarning {
  code: string;
  message: string;
  impact: string;
}

/**
 * Validates environment for spawn_agent functionality.
 * Call at TUI startup to fail fast with clear errors.
 */
export async function validateSpawnEnvironment(): Promise<ValidationResult> {
  const errors: ValidationError[] = [];
  const warnings: ValidationWarning[] = [];

  // Check 1: claude CLI in PATH
  try {
    execSync("which claude", { stdio: "pipe" });
  } catch {
    errors.push({
      code: "E_CLAUDE_NOT_FOUND",
      message: "claude CLI not found in PATH",
      resolution:
        "Install Claude Code CLI: npm install -g @anthropic-ai/claude-code",
    });
  }

  // Check 2: /tmp writable
  const tmpTestFile = path.join(os.tmpdir(), `spawn-test-${Date.now()}`);
  try {
    await fs.writeFile(tmpTestFile, "test", "utf-8");
    await fs.unlink(tmpTestFile);
  } catch (err) {
    errors.push({
      code: "E_TMP_NOT_WRITABLE",
      message: `Cannot write to temp directory: ${os.tmpdir()}`,
      resolution:
        "Ensure temp directory exists and is writable, or set TMPDIR env var",
    });
  }

  // Check 3: GOGENT_MCP_SPAWN_ENABLED not explicitly disabled
  if (process.env.GOGENT_MCP_SPAWN_ENABLED === "false") {
    warnings.push({
      code: "W_SPAWN_DISABLED",
      message: "MCP spawn is disabled via GOGENT_MCP_SPAWN_ENABLED=false",
      impact: "spawn_agent tool will not be available",
    });
  }

  // Check 4: XDG_DATA_HOME for telemetry (warning only)
  if (!process.env.XDG_DATA_HOME) {
    warnings.push({
      code: "W_XDG_DATA_HOME_MISSING",
      message: "XDG_DATA_HOME not set",
      impact: "Telemetry will use fallback ~/.local/share",
    });
  }

  // Check 5: Node.js version
  const nodeVersion = process.versions.node;
  const [major] = nodeVersion.split(".").map(Number);
  if (major < 20) {
    errors.push({
      code: "E_NODE_VERSION",
      message: `Node.js ${nodeVersion} is below minimum required version 20`,
      resolution: "Upgrade Node.js to version 20 or higher",
    });
  }

  return {
    ok: errors.length === 0,
    errors,
    warnings,
  };
}

/**
 * Formats validation result for console output.
 */
export function formatValidationResult(result: ValidationResult): string {
  const lines: string[] = [];

  if (result.ok) {
    lines.push("✅ Environment validation passed");
  } else {
    lines.push("❌ Environment validation failed");
  }

  if (result.errors.length > 0) {
    lines.push("");
    lines.push("Errors:");
    for (const err of result.errors) {
      lines.push(`  [${err.code}] ${err.message}`);
      lines.push(`    → ${err.resolution}`);
    }
  }

  if (result.warnings.length > 0) {
    lines.push("");
    lines.push("Warnings:");
    for (const warn of result.warnings) {
      lines.push(`  [${warn.code}] ${warn.message}`);
      lines.push(`    Impact: ${warn.impact}`);
    }
  }

  return lines.join("\n");
}

/**
 * Validates and throws if critical errors found.
 * Use at startup to prevent running with invalid environment.
 */
export async function assertValidSpawnEnvironment(): Promise<void> {
  const result = await validateSpawnEnvironment();

  if (!result.ok) {
    const formatted = formatValidationResult(result);
    throw new Error(`Spawn environment validation failed:\n${formatted}`);
  }

  // Log warnings but don't fail
  if (result.warnings.length > 0) {
    console.warn(formatValidationResult(result));
  }
}

