export function App({ sessionId, verbose }: AppProps): JSX.Element {
  const [mode, setMode] = useState<DemoMode>("main");
  const [loading, setLoading] = useState(!!sessionId);
  const updateSession = useStore((state) => state.updateSession);
  const totalCost = useStore((state) => state.totalCost);
  const currentSessionId = useStore((state) => state.sessionId);

  // Set verbose mode
  useEffect(() => {
    if (verbose) {
      process.env["VERBOSE"] = "1";
    }
  }, [verbose]);

  // Load session on mount if sessionId provided
  useEffect(() => {
    async function resumeSession() {
      if (!sessionId) return;

      try {
        const session = await loadSession(sessionId);
        updateSession({
          id: session.id,
          cost: session.cost,
        });

        if (verbose) {
          console.log(`[Session] Resumed: ${session.id}`);
          console.log(`[Session] Cost: $${session.cost.toFixed(4)}`);
          console.log(`[Session] Tools: ${session.tool_calls}`);
        }
      } catch (error) {
        console.error(`Failed to load session: ${sessionId}`, error);
        // Continue with new session on error
        updateSession({ id: nanoid() });
      } finally {
        setLoading(false);
      }
    }

    resumeSession();
  }, [sessionId, updateSession, verbose]);

  // Auto-save session on cost changes
  useEffect(() => {
    async function persistSession() {
      if (!currentSessionId) return;
      if (totalCost === 0) return; // Don't save empty sessions

      try {
        const tokenCount = useStore.getState().tokenCount;
        const toolCalls = tokenCount.input + tokenCount.output; // Approximate tool calls

        await saveSession({
          id: currentSessionId,
          created_at: new Date().toISOString(),
          last_used: new Date().toISOString(),
          cost: totalCost,
          tool_calls: toolCalls,
        });

        if (verbose) {
          console.log(`[Session] Saved: ${currentSessionId}`);
        }
      } catch (error) {
        console.error("Failed to save session:", error);
      }
    }

    persistSession();
  }, [totalCost, currentSessionId, verbose]);

  // Show loading state while resuming session
  if (loading) {
    return (
      <Box padding={1}>
        <Text color={colors.muted}>Loading session {sessionId}...</Text>
      </Box>
    );
  }

  useInput((input, _key) => {
    // Cycle through demo modes with number keys
    if (input === "0") setMode("main");
    if (input === "1") setMode("hello");
    if (input === "2") setMode("layout");
    if (input === "3") setMode("responsive");
    if (input === "4") setMode("borders");

    // Exit handled by Layout component (Escape) or Ink's default Ctrl+C
  });

  return (
    <Box flexDirection="column" width="100%" height="100%">
      {mode === "main" ? (
        // Main application layout (TUI-007)
        <Layout />
      ) : (
        // Spike testing modes
        <>
          {/* Header */}
          <Box borderStyle="round" borderColor={colors.primary} paddingX={2}>
            <Text bold color={colors.primary}>
              GOfortress TUI - Ink Layout Spike
            </Text>
          </Box>

          {/* Mode selector */}
          <Box paddingX={2} paddingY={1}>
            <Text dimColor color={colors.muted}>
              Press: [0] Main | [1] Hello | [2] Layout | [3] Responsive | [4] Borders | [Ctrl+C] Exit
            </Text>
          </Box>

          {/* Content area */}
          <Box flexGrow={1}>
            {mode === "hello" && (
              <Box flexDirection="column" padding={1}>
                <Text bold color={colors.primary}>
                  GOfortress TUI
                </Text>
                <Text color={colors.muted}>Hello from Ink!</Text>
                <Box marginTop={1}>
                  <Text color={colors.secondary}>
                    Use number keys to test different spike components
                  </Text>
                </Box>
              </Box>
            )}

            {mode === "layout" && <LayoutSpike />}
            {mode === "responsive" && <ResponsiveLayout />}
            {mode === "borders" && <BorderStyleTest />}
          </Box>
        </>
      )}
    </Box>
  );
}

/**
 * request_input MCP tool
 * Request text input from the user
 */

import { tool } from "@anthropic-ai/claude-agent-sdk";
import { z } from "zod";
import { useStore } from "../../store/index.js";
import type { ModalResponse } from "../../store/slices/modal.js";

export const requestInputSchema = z.object({
  prompt: z.string().min(1, "Prompt must not be empty").describe("The prompt message to show"),
  placeholder: z.string().optional().describe("Placeholder text for the input field"),
});

export const requestInputTool = tool(
  "request_input",
  "Request text input from the user",
  requestInputSchema.shape,
  async (args) => {
    const response = (await useStore.getState().enqueue({
      type: "input",
      payload: {
        prompt: args.prompt,
        placeholder: args.placeholder,
      },
    })) as Extract<ModalResponse, { type: "input" }>;

    return {
      content: [
        {
          type: "text" as const,
          text: response.value,
        },
      ],
    };
  }
);

