/**
 * Graceful shutdown handling
 * Coordinates with session persistence and Go hooks on app exit
 */

import { useStore } from "../store/index.js";
import { saveSession } from "../hooks/useSession.js";

type ShutdownHandler = () => Promise<void>;

/**
 * Registered shutdown handlers
 * Executed in order during graceful shutdown
 */
const handlers: ShutdownHandler[] = [];

/**
 * Track if shutdown is in progress to prevent duplicate execution
 */
let isShuttingDown = false;

/**
 * Register a shutdown handler
 * Handlers execute in registration order during shutdown
 */
export function onShutdown(handler: ShutdownHandler): void {
  handlers.push(handler);
}

/**
 * Initiate graceful shutdown sequence
 * 1. Save session state
 * 2. Execute registered handlers
 * 3. Allow time for Go hooks (gogent-archive)
 * 4. Exit process
 */
export async function initiateShutdown(signal: string): Promise<void> {
  // Prevent duplicate shutdown execution
  if (isShuttingDown) {
    return;
  }
  isShuttingDown = true;

  console.log(`\n[Shutdown] Received ${signal}, shutting down gracefully...`);

  try {
    // Step 1: Save session state
    const state = useStore.getState();
    if (state.sessionId) {
      console.log(`[Shutdown] Saving session ${state.sessionId}...`);
      await saveSession({
        id: state.sessionId,
        created_at: new Date().toISOString(), // Will be preserved if exists
        last_used: new Date().toISOString(),
        cost: state.totalCost,
        tool_calls: 0, // Not tracking tool calls in TUI yet
      });
      console.log("[Shutdown] Session saved");
    }

    // Step 2: Run all registered handlers
    console.log(`[Shutdown] Running ${handlers.length} shutdown handlers...`);
    for (let i = 0; i < handlers.length; i++) {
      try {
        const handler = handlers[i];
        if (handler) {
          await handler();
        }
      } catch (error) {
        console.error(`[Shutdown] Handler ${i} error:`, error);
        // Continue with other handlers even if one fails
      }
    }
    console.log("[Shutdown] Handlers complete");

    // Step 3: Allow time for Go hooks (gogent-archive runs on SessionEnd)
    // The hook needs time to write handoff and metrics
    console.log("[Shutdown] Waiting for Go hooks...");
    await new Promise((resolve) => setTimeout(resolve, 500));

    console.log("[Shutdown] Graceful shutdown complete");
  } catch (error) {
    console.error("[Shutdown] Error during shutdown:", error);
    // Continue to exit even if shutdown has errors
  } finally {
    process.exit(0);
  }
}

/**
 * Setup signal handlers for graceful shutdown
 * Handles SIGINT (Ctrl+C), SIGTERM, and uncaught exceptions
 */
export function setupSignalHandlers(): void {
  // Handle SIGINT (Ctrl+C)
  process.on("SIGINT", () => {
    void initiateShutdown("SIGINT");
  });

  // Handle SIGTERM (kill command)
  process.on("SIGTERM", () => {
    void initiateShutdown("SIGTERM");
  });

  // Handle uncaught exceptions - log and shutdown
  process.on("uncaughtException", (error) => {
    console.error("[Fatal] Uncaught exception:", error);
    void initiateShutdown("uncaughtException");
  });

  // Handle unhandled promise rejections - log but don't exit
  // This follows Node.js best practices - log and continue
  process.on("unhandledRejection", (reason, promise) => {
    console.error("[Warning] Unhandled promise rejection:", reason);
    console.error("Promise:", promise);
    // Don't exit - just log for debugging
  });

  // Handle process warnings (e.g., memory leaks)
  process.on("warning", (warning) => {
    console.warn("[Warning]", warning.name, warning.message);
  });
}

/**
 * Register cleanup for child processes
 * Ensures no orphaned processes remain after shutdown
 */
export function registerChildProcessCleanup(
  cleanup: () => Promise<void>
): void {
  onShutdown(cleanup);
}

/**
 * Get shutdown state for testing
 */
export function isShutdownInProgress(): boolean {
  return isShuttingDown;
}

/**
 * Reset shutdown state
 * Primarily for testing - allows multiple test runs
 */
export function resetShutdownState(): void {
  isShuttingDown = false;
  handlers.length = 0; // Clear handlers array
}

/**
 * Session file operations hook
 * Manages session persistence with Go-compatible format
 *
 * SESSION FILE FORMAT (CRITICAL - Must Match Go):
 * {
 *   "id": "uuid-here",
 *   "name": "optional-name",
 *   "created_at": "2026-02-01T10:00:00Z",
 *   "last_used": "2026-02-01T11:30:00Z",
 *   "cost": 0.42,
 *   "tool_calls": 127
 * }
 */

import { promises as fs } from "fs";
import { join } from "path";
import { homedir } from "os";
import type { SessionData } from "../store/types.js";

/**
 * Get session directory path
 * Allows override via environment variable for testing
 */
function getSessionDir(): string {
  const home = process.env["HOME"] || homedir();
  return join(home, ".claude", "sessions");
}

/**
 * Ensure session directory exists
 */
async function ensureSessionDir(): Promise<void> {
  const sessionDir = getSessionDir();
  try {
    await fs.mkdir(sessionDir, { recursive: true });
  } catch (error) {
    if ((error as NodeJS.ErrnoException).code !== "EEXIST") {
      throw error;
    }
  }
}

/**
 * List all sessions from ~/.claude/sessions/
 * Sorted by last_used descending (most recent first)
 * Skips invalid JSON files gracefully
 */
export async function listSessions(): Promise<SessionData[]> {
  await ensureSessionDir();
  const sessionDir = getSessionDir();

  try {
    const files = await fs.readdir(sessionDir);
    const sessions: SessionData[] = [];

    for (const file of files) {
      if (!file.endsWith(".json")) continue;

      try {
        const filePath = join(sessionDir, file);
        const content = await fs.readFile(filePath, "utf-8");
        const session = JSON.parse(content) as SessionData;

        // Validate required fields
        if (
          session.id &&
          session.created_at &&
          session.last_used &&
          typeof session.cost === "number" &&
          typeof session.tool_calls === "number"
        ) {
          sessions.push(session);
        }
      } catch (error) {
        // Skip invalid files - don't crash on corrupted JSON
        if (process.env["VERBOSE"]) {
          console.error(`Skipping invalid session file: ${file}`, error);
        }
      }
    }

    // Sort by last_used descending (most recent first)
    sessions.sort((a, b) => {
      return new Date(b.last_used).getTime() - new Date(a.last_used).getTime();
    });

    return sessions;
  } catch (error) {
    if ((error as NodeJS.ErrnoException).code === "ENOENT") {
      return []; // Directory doesn't exist yet
    }
    throw error;
  }
}

/**
 * Load specific session by ID
 * Throws if session doesn't exist or is invalid
 */
export async function loadSession(id: string): Promise<SessionData> {
  const sessionDir = getSessionDir();
  const filePath = join(sessionDir, `${id}.json`);

  try {
    const content = await fs.readFile(filePath, "utf-8");
    const session = JSON.parse(content) as SessionData;

    // Validate required fields
    if (
      !session.id ||
      !session.created_at ||
      !session.last_used ||
      typeof session.cost !== "number" ||
      typeof session.tool_calls !== "number"
    ) {
      throw new Error(`Invalid session format: ${id}`);
    }

    return session;
  } catch (error) {
    if ((error as NodeJS.ErrnoException).code === "ENOENT") {
      throw new Error(`Session not found: ${id}`);
    }
    throw error;
  }
}

/**
 * Save session to file
 * Creates/updates session file with Go-compatible format
 * Uses snake_case field names for Go compatibility
 */
export async function saveSession(session: SessionData): Promise<void> {
  await ensureSessionDir();
  const sessionDir = getSessionDir();
  const filePath = join(sessionDir, `${session.id}.json`);

  // Ensure ISO 8601 format with Z suffix
  const data: SessionData = {
    id: session.id,
    name: session.name,
    created_at: session.created_at,
    last_used: new Date().toISOString(), // Update last_used on save
    cost: session.cost,
    tool_calls: session.tool_calls,
  };

  await fs.writeFile(filePath, JSON.stringify(data, null, 2), "utf-8");
}

/**
 * Delete session file
 */
export async function deleteSession(id: string): Promise<void> {
  const sessionDir = getSessionDir();
  const filePath = join(sessionDir, `${id}.json`);

  try {
    await fs.unlink(filePath);
  } catch (error) {
    if ((error as NodeJS.ErrnoException).code === "ENOENT") {
      throw new Error(`Session not found: ${id}`);
    }
    throw error;
  }
}

/**
 * React hook for session operations
 * Provides session CRUD operations with error handling
 */
export function useSession() {
  return {
    listSessions,
    loadSession,
    saveSession,
    deleteSession,
  };
}

/**
 * Restart manager with exponential backoff
 * Handles automatic restart on crash with configurable retry logic
 */

export interface RestartConfig {
  maxAttempts: number;
  initialDelayMs: number;
  maxDelayMs: number;
  backoffMultiplier: number;
  successfulRunThresholdMs: number; // Reset backoff after this long
}

const DEFAULT_CONFIG: RestartConfig = {
  maxAttempts: 3,
  initialDelayMs: 1000,
  maxDelayMs: 30000,
  backoffMultiplier: 2,
  successfulRunThresholdMs: 60000, // 60 seconds
};

export class RestartManager {
  private attempts = 0;
  private lastAttemptTime = 0;
  private lastSuccessfulStartTime = 0;

  constructor(private config: RestartConfig = DEFAULT_CONFIG) {}

  /**
   * Check if restart should be attempted
   * Returns false if max attempts exceeded
   */
  shouldRestart(): boolean {
    return this.attempts < this.config.maxAttempts;
  }

  /**
   * Calculate delay for next restart attempt
   * Uses exponential backoff capped at maxDelayMs
   */
  getDelay(): number {
    const delay = Math.min(
      this.config.initialDelayMs *
        Math.pow(this.config.backoffMultiplier, this.attempts),
      this.config.maxDelayMs
    );
    return delay;
  }

  /**
   * Record a restart attempt
   * Updates attempt counter and timestamp
   */
  recordAttempt(): void {
    this.attempts++;
    this.lastAttemptTime = Date.now();
  }

  /**
   * Mark successful start
   * Used to detect if app ran long enough to reset backoff
   */
  recordSuccessfulStart(): void {
    this.lastSuccessfulStartTime = Date.now();
  }

  /**
   * Check if backoff should reset based on run duration
   * Resets if app ran longer than successfulRunThresholdMs
   */
  checkAndResetIfSuccessful(): void {
    if (this.lastSuccessfulStartTime === 0) {
      return;
    }

    const runDuration = Date.now() - this.lastSuccessfulStartTime;
    if (runDuration >= this.config.successfulRunThresholdMs) {
      this.reset();
    }
  }

  /**
   * Reset attempt counter
   * Called after successful run or manual reset
   */
  reset(): void {
    this.attempts = 0;
    this.lastAttemptTime = 0;
  }

  /**
   * Get current restart state for debugging
   */
  getState(): {
    attempts: number;
    maxAttempts: number;
    lastAttemptTime: number;
    canRestart: boolean;
    nextDelay: number;
  } {
    return {
      attempts: this.attempts,
      maxAttempts: this.config.maxAttempts,
      lastAttemptTime: this.lastAttemptTime,
      canRestart: this.shouldRestart(),
      nextDelay: this.getDelay(),
    };
  }
}

/**
 * Global restart manager instance
 * Singleton pattern for app-wide restart coordination
 */
let globalRestartManager: RestartManager | null = null;

export function getRestartManager(
  config?: Partial<RestartConfig>
): RestartManager {
  if (!globalRestartManager) {
    globalRestartManager = new RestartManager(
      config ? { ...DEFAULT_CONFIG, ...config } : DEFAULT_CONFIG
    );
  }
  return globalRestartManager;
}

/**
 * Reset global restart manager
 * Primarily for testing
 */
export function resetRestartManager(): void {
  globalRestartManager = null;
}

/**
 * MCP Integration Tests
 * Tests end-to-end flow: tool handler → modal queue → user response → tool return
 */

import { describe, it, expect, beforeEach } from "vitest";
import { useStore } from "../../src/store/index.js";
import { askUserTool } from "../../src/mcp/tools/askUser.js";
import { confirmActionTool } from "../../src/mcp/tools/confirmAction.js";
import { requestInputTool } from "../../src/mcp/tools/requestInput.js";
import { selectOptionTool } from "../../src/mcp/tools/selectOption.js";
import type { ModalResponse } from "../../src/store/slices/modal.js";

/**
 * Helper to simulate user response after modal is enqueued
 */
async function simulateUserResponse(
  response: ModalResponse,
  delay = 0
): Promise<void> {
  await new Promise((resolve) => setTimeout(resolve, delay));
  const queue = useStore.getState().modalQueue;
  const modal = queue[queue.length - 1];
  if (modal) {
    useStore.getState().dequeue(modal.id, response);
  }
}

describe("MCP Integration - Basic Tool Flow", () => {
  beforeEach(() => {
    useStore.setState({
      modalQueue: [],
    });
  });

  describe("ask_user tool", () => {
    it("should complete full flow: tool call → modal → user response → return value", async () => {
      // Start tool call
      const promise = askUserTool.handler({
        message: "What is your favorite color?",
      });

      // Simulate user responding after modal is enqueued
      setTimeout(() => {
        simulateUserResponse({
          type: "ask",
          value: "Blue",
        });
      }, 10);

      // Tool should return user's response
      const result = await promise;
      expect(result.content[0]?.text).toBe("Blue");

      // Queue should be empty after completion
      expect(useStore.getState().modalQueue).toHaveLength(0);
    });

    it("should handle options flow correctly", async () => {
      const promise = askUserTool.handler({
        message: "Choose a size",
        options: ["Small", "Medium", "Large"],
      });

      await new Promise((resolve) => setTimeout(resolve, 0));

      // Verify modal has options
      const modal = useStore.getState().modalQueue[0];
      expect(modal?.payload).toEqual({
        message: "Choose a size",
        options: ["Small", "Medium", "Large"],
        defaultValue: undefined,
      });

      // User selects option
      await simulateUserResponse({
        type: "ask",
        value: "Large",
      });

      const result = await promise;
      expect(result.content[0]?.text).toBe("Large");
    });

    it("should handle default value correctly", async () => {
      const promise = askUserTool.handler({
        message: "Enter your username",
        default: "guest",
      });

      await new Promise((resolve) => setTimeout(resolve, 0));

      const modal = useStore.getState().modalQueue[0];
      expect(modal?.payload).toHaveProperty("defaultValue", "guest");

      await simulateUserResponse({
        type: "ask",
        value: "alice",
      });

      const result = await promise;
      expect(result.content[0]?.text).toBe("alice");
    });
  });

  describe("confirm_action tool", () => {
    it("should complete confirmation flow with YES", async () => {
      const promise = confirmActionTool.handler({
        action: "Delete file config.yaml",
      });

      setTimeout(() => {
        simulateUserResponse({
          type: "confirm",
          confirmed: true,
          cancelled: false,
        });
      }, 10);

      const result = await promise;
      const response = JSON.parse(result.content[0]?.text ?? "{}");
      expect(response).toEqual({
        confirmed: true,
        cancelled: false,
      });

      expect(useStore.getState().modalQueue).toHaveLength(0);
    });

    it("should complete confirmation flow with NO", async () => {
      const promise = confirmActionTool.handler({
        action: "Reset database",
      });

      setTimeout(() => {
        simulateUserResponse({
          type: "confirm",
          confirmed: false,
          cancelled: false,
        });
      }, 10);

      const result = await promise;
      const response = JSON.parse(result.content[0]?.text ?? "{}");
      expect(response).toEqual({
        confirmed: false,
        cancelled: false,
      });
    });

    it("should handle user cancellation (Escape)", async () => {
      const promise = confirmActionTool.handler({
        action: "Drop table users",
        destructive: true,
      });

      await new Promise((resolve) => setTimeout(resolve, 0));

      // Verify destructive flag passed
      const modal = useStore.getState().modalQueue[0];
      expect(modal?.payload).toEqual({
        action: "Drop table users",
        destructive: true,
      });

      // User cancels
      await simulateUserResponse({
        type: "confirm",
        confirmed: false,
        cancelled: true,
      });

      const result = await promise;
      const response = JSON.parse(result.content[0]?.text ?? "{}");
      expect(response).toEqual({
        confirmed: false,
        cancelled: true,
      });
    });
  });

  describe("request_input tool", () => {
    it("should complete input flow correctly", async () => {
      const promise = requestInputTool.handler({
        prompt: "Enter your API key",
      });

      setTimeout(() => {
        simulateUserResponse({
          type: "input",
          value: "sk-test-123456",
        });
      }, 10);

      const result = await promise;
      expect(result.content[0]?.text).toBe("sk-test-123456");
      expect(useStore.getState().modalQueue).toHaveLength(0);
    });

    it("should pass placeholder to modal", async () => {
      const promise = requestInputTool.handler({
        prompt: "Enter email",
        placeholder: "user@example.com",
      });

      await new Promise((resolve) => setTimeout(resolve, 0));

      const modal = useStore.getState().modalQueue[0];
      expect(modal?.payload).toEqual({
        prompt: "Enter email",
        placeholder: "user@example.com",
      });

      await simulateUserResponse({
        type: "input",
        value: "alice@test.com",
      });

      const result = await promise;
      expect(result.content[0]?.text).toBe("alice@test.com");
    });

    it("should handle empty input", async () => {
      const promise = requestInputTool.handler({
        prompt: "Optional comment",
      });

      setTimeout(() => {
        simulateUserResponse({
          type: "input",
          value: "",
        });
      }, 10);

      const result = await promise;
      expect(result.content[0]?.text).toBe("");
    });
  });

  describe("select_option tool", () => {
    it("should complete selection flow correctly", async () => {
      const promise = selectOptionTool.handler({
        message: "Select your framework",
        options: [
          { label: "React", value: "react" },
          { label: "Vue", value: "vue" },
          { label: "Svelte", value: "svelte" },
        ],
      });

      await new Promise((resolve) => setTimeout(resolve, 0));

      // Verify modal payload
      const modal = useStore.getState().modalQueue[0];
      expect(modal?.payload).toEqual({
        message: "Select your framework",
        options: [
          { label: "React", value: "react" },
          { label: "Vue", value: "vue" },
          { label: "Svelte", value: "svelte" },
        ],
      });

      // User selects first option
      await simulateUserResponse({
        type: "select",
        selected: "react",
        index: 0,
      });

      const result = await promise;
      const response = JSON.parse(result.content[0]?.text ?? "{}");
      expect(response).toEqual({
        selected: "react",
        index: 0,
      });

      expect(useStore.getState().modalQueue).toHaveLength(0);
    });

    it("should handle selection of different indices", async () => {
      const promise = selectOptionTool.handler({
        message: "Pick a number",
        options: [
          { label: "One", value: "1" },
          { label: "Two", value: "2" },
          { label: "Three", value: "3" },
        ],
      });

      setTimeout(() => {
        simulateUserResponse({
          type: "select",
          selected: "3",
          index: 2,
        });
      }, 10);

      const result = await promise;
      const response = JSON.parse(result.content[0]?.text ?? "{}");
      expect(response).toEqual({
        selected: "3",
        index: 2,
      });
    });
  });

  describe("MCP response format validation", () => {
    it("all tools should return MCP-compliant response format", async () => {
      const promises = [
        askUserTool.handler({ message: "Test ask" }),
        confirmActionTool.handler({ action: "Test confirm" }),
        requestInputTool.handler({ prompt: "Test input" }),
        selectOptionTool.handler({
          message: "Test select",
          options: [{ label: "A", value: "a" }],
        }),
      ];

      // Respond to all
      await new Promise((resolve) => setTimeout(resolve, 0));
      const queue = useStore.getState().modalQueue;

      queue.forEach((modal) => {
        let response: ModalResponse;
        switch (modal.type) {
          case "ask":
            response = { type: "ask", value: "test" };
            break;
          case "confirm":
            response = { type: "confirm", confirmed: true, cancelled: false };
            break;
          case "input":
            response = { type: "input", value: "test" };
            break;
          case "select":
            response = { type: "select", selected: "a", index: 0 };
            break;
        }
        useStore.getState().dequeue(modal.id, response);
      });

      const results = await Promise.all(promises);

      // All should have MCP-compliant format
      results.forEach((result) => {
        expect(result).toHaveProperty("content");
        expect(Array.isArray(result.content)).toBe(true);
        expect(result.content).toHaveLength(1);
        expect(result.content[0]).toHaveProperty("type", "text");
        expect(result.content[0]).toHaveProperty("text");
        expect(typeof result.content[0]?.text).toBe("string");
      });
    });
  });
});

