import { spawnMockClaude } from "../../../tests/mocks/spawnHelper";
import { resetProcessRegistry, getProcessRegistry } from "../../spawn/processRegistry";
import {
  buildCliArgs,
  parseCliOutput,
  getCurrentNestingLevel,
  validateNestingDepth,
} from "./spawnAgent";

// Note: Full tests require mock CLI infrastructure from MCP-SPAWN-003

describe("spawn_agent tool", () => {
  beforeEach(() => {
    resetProcessRegistry();
  });

  afterEach(() => {
    resetProcessRegistry();
  });

  describe("buildCliArgs", () => {
    it("should include -p and --output-format json", () => {
      const args = buildCliArgs({});

      expect(args).toContain("-p");
      expect(args).toContain("--output-format");
      expect(args).toContain("json");
    });

    it("should include model when specified", () => {
      const args = buildCliArgs({ model: "opus" });

      expect(args).toContain("--model");
      expect(args).toContain("opus");
    });

    it("should include allowedTools when specified", () => {
      const args = buildCliArgs({ allowedTools: ["Read", "Glob", "Grep"] });

      expect(args).toContain("--allowedTools");
      expect(args).toContain("Read,Glob,Grep");
    });

    it("should use delegate permission mode", () => {
      const args = buildCliArgs({});

      expect(args).toContain("--permission-mode");
      expect(args).toContain("delegate");
    });

    it("should include maxBudget when specified", () => {
      const args = buildCliArgs({ maxBudget: 0.50 });

      expect(args).toContain("--max-budget-usd");
      expect(args).toContain("0.5");
    });
  });

  describe("parseCliOutput", () => {
    it("should parse valid JSON output", () => {
      const output = JSON.stringify({
        result: "Analysis complete",
        cost_usd: 0.05,
        num_turns: 3,
      });

      const parsed = parseCliOutput(output);

      expect(parsed.result).toBe("Analysis complete");
      expect(parsed.cost).toBe(0.05);
      expect(parsed.turns).toBe(3);
    });

    it("should return raw output for invalid JSON", () => {
      const output = "This is not JSON";
      const parsed = parseCliOutput(output);

      expect(parsed.result).toBe("This is not JSON");
    });

    it("should handle alternate JSON field names", () => {
      const output = JSON.stringify({
        output: "Result text",
        total_cost_usd: 0.12,
        num_turns: 5,
      });

      const parsed = parseCliOutput(output);

      expect(parsed.result).toBe("Result text");
      expect(parsed.cost).toBe(0.12);
      expect(parsed.turns).toBe(5);
    });
  });

  describe("getCurrentNestingLevel", () => {
    it("should return 0 when not set", () => {
      const originalEnv = process.env.GOGENT_NESTING_LEVEL;
      delete process.env.GOGENT_NESTING_LEVEL;

      expect(getCurrentNestingLevel()).toBe(0);

      process.env.GOGENT_NESTING_LEVEL = originalEnv;
    });

    it("should return parsed level when set", () => {
      const originalEnv = process.env.GOGENT_NESTING_LEVEL;
      process.env.GOGENT_NESTING_LEVEL = "2";

      expect(getCurrentNestingLevel()).toBe(2);

      process.env.GOGENT_NESTING_LEVEL = originalEnv;
    });

    it("should return 0 for invalid nesting level", () => {
      const originalEnv = process.env.GOGENT_NESTING_LEVEL;
      process.env.GOGENT_NESTING_LEVEL = "invalid";

      expect(getCurrentNestingLevel()).toBe(0);

      process.env.GOGENT_NESTING_LEVEL = originalEnv;
    });
  });

  describe("nesting depth validation", () => {
    it("should reject spawn when at MAX_NESTING_DEPTH", () => {
      const originalEnv = process.env.GOGENT_NESTING_LEVEL;
      process.env.GOGENT_NESTING_LEVEL = "10"; // MAX_NESTING_DEPTH

      const error = validateNestingDepth();

      expect(error).not.toBeNull();
      expect(error).toContain("Maximum nesting depth");
      expect(error).toContain("10");

      process.env.GOGENT_NESTING_LEVEL = originalEnv;
    });

    it("should allow spawn when under MAX_NESTING_DEPTH", () => {
      const originalEnv = process.env.GOGENT_NESTING_LEVEL;
      process.env.GOGENT_NESTING_LEVEL = "5";

      const error = validateNestingDepth();

      expect(error).toBeNull();

      process.env.GOGENT_NESTING_LEVEL = originalEnv;
    });

    it("should allow spawn at level 0", () => {
      const originalEnv = process.env.GOGENT_NESTING_LEVEL;
      delete process.env.GOGENT_NESTING_LEVEL;

      const error = validateNestingDepth();

      expect(error).toBeNull();

      process.env.GOGENT_NESTING_LEVEL = originalEnv;
    });
  });

  // Integration tests with mock CLI
  describe("integration with mock CLI", () => {
    it("should handle successful spawn", async () => {
      const result = await spawnMockClaude(
        { behavior: "success", output: "Test output" },
        "Test prompt"
      );

      expect(result.exitCode).toBe(0);
      expect(result.stdout).toContain("success");
    });

    it("should handle timeout", async () => {
      const result = await spawnMockClaude(
        { behavior: "timeout" },
        "Test prompt",
        100 // 100ms timeout
      );

      expect(result.killed).toBe(true);
    });

    it("should handle error response", async () => {
      const result = await spawnMockClaude(
        { behavior: "error_max_turns" },
        "Test prompt"
      );

      expect(result.exitCode).toBe(1);
    });
  });
});

import { execSync } from "child_process";
import * as fs from "fs/promises";
import * as path from "path";
import * as os from "os";

export interface ValidationResult {
  ok: boolean;
  errors: ValidationError[];
  warnings: ValidationWarning[];
}

export interface ValidationError {
  code: string;
  message: string;
  resolution: string;
}

export interface ValidationWarning {
  code: string;
  message: string;
  impact: string;
}

/**
 * Validates environment for spawn_agent functionality.
 * Call at TUI startup to fail fast with clear errors.
 */
export async function validateSpawnEnvironment(): Promise<ValidationResult> {
  const errors: ValidationError[] = [];
  const warnings: ValidationWarning[] = [];

  // Check 1: claude CLI in PATH
  try {
    execSync("which claude", { stdio: "pipe" });
  } catch {
    errors.push({
      code: "E_CLAUDE_NOT_FOUND",
      message: "claude CLI not found in PATH",
      resolution:
        "Install Claude Code CLI: npm install -g @anthropic-ai/claude-code",
    });
  }

  // Check 2: /tmp writable
  const tmpTestFile = path.join(os.tmpdir(), `spawn-test-${Date.now()}`);
  try {
    await fs.writeFile(tmpTestFile, "test", "utf-8");
    await fs.unlink(tmpTestFile);
  } catch (err) {
    errors.push({
      code: "E_TMP_NOT_WRITABLE",
      message: `Cannot write to temp directory: ${os.tmpdir()}`,
      resolution:
        "Ensure temp directory exists and is writable, or set TMPDIR env var",
    });
  }

  // Check 3: GOGENT_MCP_SPAWN_ENABLED not explicitly disabled
  if (process.env.GOGENT_MCP_SPAWN_ENABLED === "false") {
    warnings.push({
      code: "W_SPAWN_DISABLED",
      message: "MCP spawn is disabled via GOGENT_MCP_SPAWN_ENABLED=false",
      impact: "spawn_agent tool will not be available",
    });
  }

  // Check 4: XDG_DATA_HOME for telemetry (warning only)
  if (!process.env.XDG_DATA_HOME) {
    warnings.push({
      code: "W_XDG_DATA_HOME_MISSING",
      message: "XDG_DATA_HOME not set",
      impact: "Telemetry will use fallback ~/.local/share",
    });
  }

  // Check 5: Node.js version
  const nodeVersion = process.versions.node;
  const [major] = nodeVersion.split(".").map(Number);
  if (major < 20) {
    errors.push({
      code: "E_NODE_VERSION",
      message: `Node.js ${nodeVersion} is below minimum required version 20`,
      resolution: "Upgrade Node.js to version 20 or higher",
    });
  }

  return {
    ok: errors.length === 0,
    errors,
    warnings,
  };
}

/**
 * Formats validation result for console output.
 */
export function formatValidationResult(result: ValidationResult): string {
  const lines: string[] = [];

  if (result.ok) {
    lines.push("✅ Environment validation passed");
  } else {
    lines.push("❌ Environment validation failed");
  }

  if (result.errors.length > 0) {
    lines.push("");
    lines.push("Errors:");
    for (const err of result.errors) {
      lines.push(`  [${err.code}] ${err.message}`);
      lines.push(`    → ${err.resolution}`);
    }
  }

  if (result.warnings.length > 0) {
    lines.push("");
    lines.push("Warnings:");
    for (const warn of result.warnings) {
      lines.push(`  [${warn.code}] ${warn.message}`);
      lines.push(`    Impact: ${warn.impact}`);
    }
  }

  return lines.join("\n");
}

/**
 * Validates and throws if critical errors found.
 * Use at startup to prevent running with invalid environment.
 */
export async function assertValidSpawnEnvironment(): Promise<void> {
  const result = await validateSpawnEnvironment();

  if (!result.ok) {
    const formatted = formatValidationResult(result);
    throw new Error(`Spawn environment validation failed:\n${formatted}`);
  }

  // Log warnings but don't fail
  if (result.warnings.length > 0) {
    console.warn(formatValidationResult(result));
  }
}

import React from "react";
import { Box, useStdout } from "ink";
import { useStore } from "../store/index.js";
import { useKeymap, KeyBinding } from "../hooks/useKeymap.js";
import { useAgentTree } from "../hooks/useAgentTree.js";
import { createGlobalBindings } from "../config/keybindings.js";
import { Banner } from "./Banner.js";
import { ClaudePanel } from "./ClaudePanel.js";
import { AgentTree } from "./AgentTree.js";
import { AgentDetail } from "./AgentDetail.js";
import { ModalOverlay } from "./Modal.js";
import { colors, borders } from "../config/theme.js";

// Fixed heights
const BANNER_HEIGHT = 3; // Banner takes 3 rows

/**
 * Layout component - main 2-panel split (70/30) with focus management
 *
 * Features:
 * - Left panel (70%): Claude conversation
 * - Right panel (30%): Agent tree (60%) + Agent detail (40%)
 * - Global keyboard bindings (Tab, Escape, Ctrl+C, Ctrl+L)
 * - Focus indicated by border color (cyan/gray from theme)
 * - Modal overlay renders when queue is non-empty
 * - Modal captures all input when active
 */
export function Layout(): JSX.Element {
  const { focusedPanel, setFocusedPanel, modalQueue, clearMessages } = useStore();
  const { selectPrevious, selectNext } = useAgentTree();
  const { stdout } = useStdout();

  // Calculate available height for content area
  const terminalHeight = stdout?.rows ?? 24;
  const contentHeight = terminalHeight - BANNER_HEIGHT;

  // Global key bindings (only active when no modal is present)
  const globalBindings = createGlobalBindings({
    toggleFocus: () => {
      setFocusedPanel(focusedPanel === "claude" ? "agents" : "claude");
    },
    handleEscape: () => {
      // If modal is active, cancel it; otherwise exit
      if (modalQueue.length > 0 && modalQueue[0]) {
        const modal = modalQueue[0];
        useStore.getState().cancel(modal.id);
      } else {
        process.exit(0);
      }
    },
    forceQuit: () => {
      process.exit(0);
    },
    clearScreen: () => {
      clearMessages();
    },
  });

  // Agent tree navigation bindings (only when agents panel focused)
  const agentBindings: KeyBinding[] = [
    { key: "up", action: selectPrevious, description: "Select previous agent" },
    { key: "down", action: selectNext, description: "Select next agent" },
  ];

  // Only enable global bindings when no modal is active
  useKeymap(globalBindings, modalQueue.length === 0);

  // Only enable agent navigation when agents panel focused and no modal
  useKeymap(agentBindings, focusedPanel === "agents" && modalQueue.length === 0);

  // Calculate right panel heights (fixed row counts)
  const agentTreeHeight = Math.floor(contentHeight * 0.6);
  const agentDetailHeight = contentHeight - agentTreeHeight;

  return (
    <Box flexDirection="column" height={terminalHeight}>
      {/* Banner - FIXED at top */}
      <Box height={BANNER_HEIGHT}>
        <Banner />
      </Box>

      {/* Content area - FIXED height */}
      <Box flexDirection="row" height={contentHeight}>
        {/* Left Panel: Claude conversation (70%) */}
        <Box width="70%" height={contentHeight}>
          <ClaudePanel focused={focusedPanel === "claude"} maxHeight={contentHeight - 2} />
        </Box>

        {/* Right Panel: Agent tree + detail (30%) */}
        <Box width="30%" flexDirection="column" height={contentHeight}>
          {/* Agent Tree (60% of right panel) */}
          <Box
            height={agentTreeHeight}
            borderStyle={borders.panel}
            borderColor={focusedPanel === "agents" ? colors.focused : colors.unfocused}
            flexDirection="column"
          >
            <AgentTree focused={focusedPanel === "agents"} />
          </Box>

          {/* Agent Detail (40% of right panel) */}
          <Box
            height={agentDetailHeight}
            borderStyle={borders.panel}
            borderColor={colors.muted}
            flexDirection="column"
          >
            <AgentDetail focused={false} />
          </Box>
        </Box>
      </Box>

      {/* Modal overlay (rendered when queue is non-empty) */}
      {modalQueue.length > 0 && modalQueue[0] && <ModalOverlay request={modalQueue[0]} />}
    </Box>
  );
}

