import React, { useState, useEffect } from "react";
import { Box, Text, useInput } from "ink";
import { colors } from "./config/theme.js";
import { Layout } from "./components/Layout.js";
import { LayoutSpike } from "./components/LayoutSpike.js";
import { ResponsiveLayout } from "./components/ResponsiveLayout.js";
import { BorderStyleTest } from "./components/BorderStyleTest.js";
import { loadSession, saveSession } from "./hooks/useSession.js";
import { useStore } from "./store/index.js";
import { nanoid } from "nanoid";

type DemoMode = "main" | "hello" | "layout" | "responsive" | "borders";

interface AppProps {
  sessionId?: string;
  verbose?: boolean;
}

/**
 * Root component for GOfortress TUI
 * Entry point for the application UI structure
 * Includes spike testing modes for layout validation
 * Handles session persistence and resumption
 */
export function App({ sessionId, verbose }: AppProps): JSX.Element {
  const [mode, setMode] = useState<DemoMode>("main");
  const [loading, setLoading] = useState(!!sessionId);
  const updateSession = useStore((state) => state.updateSession);
  const totalCost = useStore((state) => state.totalCost);
  const currentSessionId = useStore((state) => state.sessionId);

  // Set verbose mode
  useEffect(() => {
    if (verbose) {
      process.env["VERBOSE"] = "1";
    }
  }, [verbose]);

  // Load session on mount if sessionId provided
  useEffect(() => {
    async function resumeSession() {
      if (!sessionId) return;

      try {
        const session = await loadSession(sessionId);
        updateSession({
          id: session.id,
          cost: session.cost,
        });

        if (verbose) {
          console.log(`[Session] Resumed: ${session.id}`);
          console.log(`[Session] Cost: $${session.cost.toFixed(4)}`);
          console.log(`[Session] Tools: ${session.tool_calls}`);
        }
      } catch (error) {
        console.error(`Failed to load session: ${sessionId}`, error);
        // Continue with new session on error
        updateSession({ id: nanoid() });
      } finally {
        setLoading(false);
      }
    }

    resumeSession();
  }, [sessionId, updateSession, verbose]);

  // Auto-save session on cost changes
  useEffect(() => {
    async function persistSession() {
      if (!currentSessionId) return;
      if (totalCost === 0) return; // Don't save empty sessions

      try {
        const tokenCount = useStore.getState().tokenCount;
        const toolCalls = tokenCount.input + tokenCount.output; // Approximate tool calls

        await saveSession({
          id: currentSessionId,
          created_at: new Date().toISOString(),
          last_used: new Date().toISOString(),
          cost: totalCost,
          tool_calls: toolCalls,
        });

        if (verbose) {
          console.log(`[Session] Saved: ${currentSessionId}`);
        }
      } catch (error) {
        console.error("Failed to save session:", error);
      }
    }

    persistSession();
  }, [totalCost, currentSessionId, verbose]);

  // Show loading state while resuming session
  if (loading) {
    return (
      <Box padding={1}>
        <Text color={colors.muted}>Loading session {sessionId}...</Text>
      </Box>
    );
  }

  useInput((input, _key) => {
    // Cycle through demo modes with number keys
    if (input === "0") setMode("main");
    if (input === "1") setMode("hello");
    if (input === "2") setMode("layout");
    if (input === "3") setMode("responsive");
    if (input === "4") setMode("borders");

    // Exit handled by Layout component (Escape) or Ink's default Ctrl+C
  });

  return (
    <Box flexDirection="column" width="100%" height="100%">
      {mode === "main" ? (
        // Main application layout (TUI-007)
        <Layout />
      ) : (
        // Spike testing modes
        <>
          {/* Header */}
          <Box borderStyle="round" borderColor={colors.primary} paddingX={2}>
            <Text bold color={colors.primary}>
              GOfortress TUI - Ink Layout Spike
            </Text>
          </Box>

          {/* Mode selector */}
          <Box paddingX={2} paddingY={1}>
            <Text dimColor color={colors.muted}>
              Press: [0] Main | [1] Hello | [2] Layout | [3] Responsive | [4] Borders | [Ctrl+C] Exit
            </Text>
          </Box>

          {/* Content area */}
          <Box flexGrow={1}>
            {mode === "hello" && (
              <Box flexDirection="column" padding={1}>
                <Text bold color={colors.primary}>
                  GOfortress TUI
                </Text>
                <Text color={colors.muted}>Hello from Ink!</Text>
                <Box marginTop={1}>
                  <Text color={colors.secondary}>
                    Use number keys to test different spike components
                  </Text>
                </Box>
              </Box>
            )}

            {mode === "layout" && <LayoutSpike />}
            {mode === "responsive" && <ResponsiveLayout />}
            {mode === "borders" && <BorderStyleTest />}
          </Box>
        </>
      )}
    </Box>
  );
}

import React from "react";
import { Box, useStdout } from "ink";
import { useStore } from "../store/index.js";
import { useKeymap, KeyBinding } from "../hooks/useKeymap.js";
import { useAgentTree } from "../hooks/useAgentTree.js";
import { createGlobalBindings } from "../config/keybindings.js";
import { Banner } from "./Banner.js";
import { ClaudePanel } from "./ClaudePanel.js";
import { AgentTree } from "./AgentTree.js";
import { AgentDetail } from "./AgentDetail.js";
import { ModalOverlay } from "./Modal.js";
import { colors, borders } from "../config/theme.js";

// Fixed heights
const BANNER_HEIGHT = 3; // Banner takes 3 rows

/**
 * Layout component - main 2-panel split (70/30) with focus management
 *
 * Features:
 * - Left panel (70%): Claude conversation
 * - Right panel (30%): Agent tree (60%) + Agent detail (40%)
 * - Global keyboard bindings (Tab, Escape, Ctrl+C, Ctrl+L)
 * - Focus indicated by border color (cyan/gray from theme)
 * - Modal overlay renders when queue is non-empty
 * - Modal captures all input when active
 */
export function Layout(): JSX.Element {
  const { focusedPanel, setFocusedPanel, modalQueue, clearMessages } = useStore();
  const { selectPrevious, selectNext } = useAgentTree();
  const { stdout } = useStdout();

  // Calculate available height for content area
  const terminalHeight = stdout?.rows ?? 24;
  const contentHeight = terminalHeight - BANNER_HEIGHT;

  // Global key bindings (only active when no modal is present)
  const globalBindings = createGlobalBindings({
    toggleFocus: () => {
      setFocusedPanel(focusedPanel === "claude" ? "agents" : "claude");
    },
    handleEscape: () => {
      // If modal is active, cancel it; otherwise exit
      if (modalQueue.length > 0 && modalQueue[0]) {
        const modal = modalQueue[0];
        useStore.getState().cancel(modal.id);
      } else {
        process.exit(0);
      }
    },
    forceQuit: () => {
      process.exit(0);
    },
    clearScreen: () => {
      clearMessages();
    },
  });

  // Agent tree navigation bindings (only when agents panel focused)
  const agentBindings: KeyBinding[] = [
    { key: "up", action: selectPrevious, description: "Select previous agent" },
    { key: "down", action: selectNext, description: "Select next agent" },
  ];

  // Only enable global bindings when no modal is active
  useKeymap(globalBindings, modalQueue.length === 0);

  // Only enable agent navigation when agents panel focused and no modal
  useKeymap(agentBindings, focusedPanel === "agents" && modalQueue.length === 0);

  // Calculate right panel heights (fixed row counts)
  const agentTreeHeight = Math.floor(contentHeight * 0.6);
  const agentDetailHeight = contentHeight - agentTreeHeight;

  return (
    <Box flexDirection="column" height={terminalHeight}>
      {/* Banner - FIXED at top */}
      <Box height={BANNER_HEIGHT}>
        <Banner />
      </Box>

      {/* Content area - FIXED height */}
      <Box flexDirection="row" height={contentHeight}>
        {/* Left Panel: Claude conversation (70%) */}
        <Box width="70%" height={contentHeight}>
          <ClaudePanel focused={focusedPanel === "claude"} maxHeight={contentHeight - 2} />
        </Box>

        {/* Right Panel: Agent tree + detail (30%) */}
        <Box width="30%" flexDirection="column" height={contentHeight}>
          {/* Agent Tree (60% of right panel) */}
          <Box
            height={agentTreeHeight}
            borderStyle={borders.panel}
            borderColor={focusedPanel === "agents" ? colors.focused : colors.unfocused}
            flexDirection="column"
          >
            <AgentTree focused={focusedPanel === "agents"} />
          </Box>

          {/* Agent Detail (40% of right panel) */}
          <Box
            height={agentDetailHeight}
            borderStyle={borders.panel}
            borderColor={colors.muted}
            flexDirection="column"
          >
            <AgentDetail focused={false} />
          </Box>
        </Box>
      </Box>

      {/* Modal overlay (rendered when queue is non-empty) */}
      {modalQueue.length > 0 && modalQueue[0] && <ModalOverlay request={modalQueue[0]} />}
    </Box>
  );
}

