/**
 * Viewport primitive - scrollable list container
 * Handles scrolling, resize, and position tracking for message lists
 */

import React, { useState, useEffect, useMemo } from "react";
import { Box, Text, useInput } from "ink";
import { colors } from "../../config/theme.js";

export interface ViewportProps<T> {
  /**
   * Array of items to render
   */
  items: T[];

  /**
   * Render function for each item
   */
  renderItem: (item: T, index: number) => React.ReactNode;

  /**
   * Viewport height (number of visible items)
   * @default 10
   */
  height?: number;

  /**
   * Whether viewport has focus for scroll controls
   * @default false
   */
  focused?: boolean;

  /**
   * Auto-scroll to bottom when new items added
   * @default true
   */
  autoScroll?: boolean;
}

/**
 * Scrollable viewport for rendering lists
 * Features:
 * - Arrow key scrolling (when focused)
 * - Auto-scroll to bottom (configurable)
 * - Scroll position preserved on resize
 * - Page up/down support
 */
export function Viewport<T>({
  items,
  renderItem,
  height = 10,
  focused = false,
  autoScroll = true,
}: ViewportProps<T>): JSX.Element {
  const [scrollOffset, setScrollOffset] = useState(0);

  // Auto-scroll to bottom when new items arrive
  useEffect(() => {
    if (autoScroll && items.length > height) {
      setScrollOffset(Math.max(0, items.length - height));
    }
  }, [items.length, height, autoScroll]);

  // Clamp scroll offset when items or height changes
  const maxOffset = useMemo(() => {
    return Math.max(0, items.length - height);
  }, [items.length, height]);

  useEffect(() => {
    setScrollOffset((prev) => Math.min(prev, maxOffset));
  }, [maxOffset]);

  // Scroll controls (only active when focused)
  useInput(
    (input, key) => {
      if (!focused) return;

      if (key.upArrow) {
        setScrollOffset((prev) => Math.max(0, prev - 1));
      } else if (key.downArrow) {
        setScrollOffset((prev) => Math.min(maxOffset, prev + 1));
      } else if (key.pageUp) {
        setScrollOffset((prev) => Math.max(0, prev - height));
      } else if (key.pageDown) {
        setScrollOffset((prev) => Math.min(maxOffset, prev + height));
      }
    },
    { isActive: focused }
  );

  // Slice visible items
  const visibleItems = useMemo(() => {
    return items.slice(scrollOffset, scrollOffset + height);
  }, [items, scrollOffset, height]);

  // Scroll indicator
  const showScrollIndicator = items.length > height;
  const scrollPercentage =
    maxOffset > 0 ? Math.round((scrollOffset / maxOffset) * 100) : 100;

  return (
    <Box flexDirection="column" flexGrow={1}>
      {/* Message list */}
      <Box flexDirection="column" flexGrow={1}>
        {visibleItems.length === 0 ? (
          <Text color={colors.muted} italic>
            No messages yet. Start a conversation!
          </Text>
        ) : (
          visibleItems.map((item, index) => {
            // Use stable ID if available, fallback to global index (not scrollOffset-dependent)
            const itemWithId = item as { id?: string };
            const globalIndex = scrollOffset + index;
            const key = itemWithId.id ?? `viewport-item-${globalIndex}`;
            return (
              <Box key={key} flexDirection="column">
                {renderItem(item, globalIndex)}
              </Box>
            );
          })
        )}
      </Box>

      {/* Scroll indicator */}
      {showScrollIndicator && (
        <Box justifyContent="flex-end">
          <Text color={colors.muted} dimColor>
            [{scrollOffset + 1}-{Math.min(scrollOffset + height, items.length)}/
            {items.length}] {scrollPercentage}%
          </Text>
        </Box>
      )}
    </Box>
  );
}

import React from "react";
import { render } from "ink";
import { App } from "./App.js";
import { parseCLI } from "./cli.js";
import { listSessions } from "./hooks/useSession.js";
import { ListSessions } from "./commands/list.jsx";
import { setupSignalHandlers } from "./lifecycle/shutdown.js";
import { getRestartManager } from "./lifecycle/restart.js";
import { validateSpawnEnvironment, formatValidationResult } from "./spawn/validation.js";

/**
 * GOfortress TUI Entry Point
 * Renders the main App component in the terminal with lifecycle management
 */

async function main() {
  // Setup graceful shutdown handlers first
  setupSignalHandlers();

  // Validate spawn environment before starting
  // Errors are logged but don't block startup - allows running with spawn disabled
  try {
    const validationResult = await validateSpawnEnvironment();
    if (!validationResult.ok || validationResult.warnings.length > 0) {
      console.error(formatValidationResult(validationResult));
      if (!validationResult.ok) {
        console.error("\n⚠️  Some spawn features may be unavailable\n");
      }
    }
  } catch (err) {
    console.error("Environment validation error:", err instanceof Error ? err.message : err);
    console.error("⚠️  Continuing with warnings - some features may be unavailable\n");
  }

  const options = parseCLI();
  const restartManager = getRestartManager();

  // Handle --list flag
  if (options.list) {
    const sessions = await listSessions();
    const { waitUntilExit } = render(<ListSessions sessions={sessions} />);
    await waitUntilExit();
    process.exit(0);
  }

  // Handle --legacy flag (fallback to Go TUI)
  if (options.legacy) {
    console.error("Legacy mode: Falling back to Go TUI");
    console.error("Run: claude-tui (Go binary)");
    process.exit(1);
  }

  // Record successful start for backoff reset detection
  restartManager.recordSuccessfulStart();

  // Normal mode: render main app
  render(<App sessionId={options.session} verbose={options.verbose} />);
}

/**
 * Restart wrapper with exponential backoff
 * Catches crashes and retries with increasing delays
 */
async function runWithRestart() {
  const restartManager = getRestartManager();

  while (true) {
    try {
      await main();
      // Normal exit - check if we should reset backoff
      restartManager.checkAndResetIfSuccessful();
      break;
    } catch (error) {
      console.error("\n[Restart] App crashed:", error);

      // Check if we should restart
      if (!restartManager.shouldRestart()) {
        console.error("[Restart] Max restart attempts reached");
        console.error("[Restart] Giving up");
        process.exit(1);
      }

      // Calculate delay and log restart info
      const delay = restartManager.getDelay();
      const state = restartManager.getState();
      console.error(
        `[Restart] Attempt ${state.attempts + 1}/${state.maxAttempts} - waiting ${delay}ms...`
      );

      // Record this attempt
      restartManager.recordAttempt();

      // Wait before restarting
      await new Promise((resolve) => setTimeout(resolve, delay));

      console.error("[Restart] Restarting app...\n");
    }
  }
}

runWithRestart().catch((error) => {
  console.error("Fatal error in restart manager:", error);
  process.exit(1);
});

/**
 * ClaudePanel - Main conversation panel
 * Features:
 * - Message viewport with scrolling
 * - Text input with submit handling and history navigation
 * - Markdown rendering
 * - Streaming state management
 * - Visual distinction between user/assistant messages
 * - Up/Down arrow keys for input history (TUI-005 integration)
 */

import React, { useState, useRef } from "react";
import { Box, Text } from "ink";
import { useStore } from "../store/index.js";
import { useKeymap } from "../hooks/useKeymap.js";
import { createClaudePanelBindings } from "../config/keybindings.js";
import { useClaudeQuery } from "../hooks/useClaudeQuery.js";
import { Viewport } from "./primitives/Viewport.js";
import { TextInput } from "./primitives/TextInput.js";
import { Spinner } from "./primitives/Spinner.js";
// Removed: import { renderMarkdown } - causes ANSI conflicts with Ink
import { colors, borders } from "../config/theme.js";
import type { Message, ContentBlock } from "../store/types.js";

export interface ClaudePanelProps {
  /**
   * Whether this panel has focus
   */
  focused: boolean;
  /**
   * Maximum height for the message viewport in rows
   */
  maxHeight?: number;
}

/**
 * Render a single message with role-based styling
 */
function MessageItem({ message }: { message: Message }): JSX.Element {
  // Determine message color based on role
  const roleColor =
    message.role === "user"
      ? colors.userMessage
      : message.role === "assistant"
        ? colors.assistantMessage
        : colors.systemMessage;

  // Extract text content from content blocks
  const textContent = message.content
    .filter((block): block is Extract<ContentBlock, { type: "text" }> => block.type === "text")
    .map((block) => block.text)
    .join("\n");

  // Render tool use/results (simplified for now)
  const toolBlocks = message.content.filter(
    (block) => block.type === "tool_use" || block.type === "tool_result"
  );

  return (
    <Box flexDirection="column" marginY={0} paddingBottom={1}>
      {/* Role header */}
      <Box>
        <Text bold color={roleColor}>
          {message.role === "user" ? "You" : message.role === "assistant" ? "Claude" : "System"}
        </Text>
        {message.partial && (
          <Text color={colors.muted}> (streaming...)</Text>
        )}
      </Box>

      {/* Text content - render each line separately for proper Ink handling */}
      {textContent && (
        <Box flexDirection="column" paddingLeft={2}>
          {textContent.split('\n').map((line, idx) => (
            <Text key={`${message.id}-line-${idx}`}>{line || ' '}</Text>
          ))}
        </Box>
      )}

      {/* Tool blocks (simplified display) */}
      {toolBlocks.map((block) => {
        // Use stable ID for tool blocks
        const blockId = block.type === "tool_use"
          ? block.id
          : block.type === "tool_result"
            ? block.tool_use_id
            : `unknown-${Math.random()}`;

        return (
          <Box key={blockId} paddingLeft={2}>
            {block.type === "tool_use" && (
              <Text color={colors.accent} dimColor>
                [Tool: {block.name}]
              </Text>
            )}
            {block.type === "tool_result" && (
              <Text color={colors.muted} dimColor>
                [Tool result]
              </Text>
            )}
          </Box>
        );
      })}
    </Box>
  );
}

/**
 * Main conversation panel with messages and input
 */
export function ClaudePanel({ focused, maxHeight = 20 }: ClaudePanelProps): JSX.Element {
  const {
    messages,
    streaming,
    addToHistory,
    navigateHistory,
    resetHistoryIndex,
    modalQueue,
    isPlanMode,
  } = useStore();
  const { sendMessage, setModel, error } = useClaudeQuery();
  const [input, setInput] = useState("");
  const currentInputRef = useRef(""); // Store current input when navigating history
  const isPlan = isPlanMode(); // Compute plan mode state

  // Helper to add system messages
  const addSystemMessage = (text: string): void => {
    useStore.getState().addMessage({
      role: "system",
      content: [{ type: "text", text }],
      partial: false,
    });
  };

  // Handle /model command
  const handleModelCommand = async (arg: string): Promise<void> => {
    if (arg) {
      // Direct model set: /model haiku
      // Use short aliases - SDK prefers these and resolves to latest version
      const MODEL_ALIASES: Record<string, string> = {
        "haiku": "haiku",
        "sonnet": "sonnet",
        "opus": "opus",
      };
      const modelId = MODEL_ALIASES[arg.toLowerCase()] || arg;

      console.log("[/model] Setting model to:", modelId);

      // Try setModel first (works if query active AND in streaming input mode)
      const success = await setModel(modelId);
      if (success) {
        addSystemMessage(`Model switched to: ${modelId}`);
      } else {
        // No active query - store preference for next message
        console.log("[/model] No active query, storing preference:", modelId);
        useStore.getState().setPreferredModel(modelId);
        addSystemMessage(`Model set to: ${modelId}. Will apply on next message.`);
      }
    } else {
      // Show model selector modal - use short aliases
      const result = await useStore.getState().enqueue({
        type: "select",
        payload: {
          message: "Select a model:",
          options: [
            {
              label: "Haiku (fast, cheap)",
              value: "haiku",
            },
            {
              label: "Sonnet (balanced)",
              value: "sonnet",
            },
            {
              label: "Opus (powerful)",
              value: "opus",
            },
          ],
        },
      });

      if (result.type === "select" && result.selected) {
        // Try setModel first (works if query active)
        const success = await setModel(result.selected);
        if (success) {
          addSystemMessage(`Model switched to: ${result.selected}`);
        } else {
          // No active query - store preference for next message
          useStore.getState().setPreferredModel(result.selected);
          addSystemMessage(`Model set to: ${result.selected}. Will apply on next message.`);
        }
      }
    }
  };

  // Handle message submission
  const handleSubmit = (): void => {
    const trimmedInput = input.trim();
    if (!trimmedInput || streaming) {
      return;
    }

    // Check for known slash commands (unknown commands pass through to Claude)
    if (trimmedInput.startsWith("/")) {
      const [command, ...args] = trimmedInput.slice(1).split(" ");

      // Guard against empty command (just "/" typed)
      if (!command) {
        setInput("");
        return;
      }

      // Handle known commands - these return early
      switch (command.toLowerCase()) {
        case "model":
          void handleModelCommand(args.join(" "));
          setInput("");
          return;

        case "clear":
          useStore.getState().clearMessages();
          setInput("");
          return;

        case "help":
          addSystemMessage(
            "Available commands:\n" +
              "  /model [haiku|sonnet|opus] - Switch model\n" +
              "  /clear - Clear message history\n" +
              "  /help - Show this help"
          );
          setInput("");
          return;

        default:
          // Unknown command - fall through to normal submission
          break;
      }
      // Execution continues here for unknown slash commands
    }

    // Normal message submission (reached by regular messages and unknown slash commands)
    // Add to input history (TUI-005)
    addToHistory(trimmedInput);

    // Clear input and reset history navigation
    setInput("");
    currentInputRef.current = "";
    resetHistoryIndex();

    // Send to Claude API
    void sendMessage(trimmedInput);
  };

  // Navigate to previous input in history (up arrow)
  const handleHistoryPrev = (): void => {
    // Save current input if we're starting navigation
    const historyIndex = useStore.getState().inputHistoryIndex;
    if (historyIndex === -1) {
      currentInputRef.current = input;
    }

    const historyItem = navigateHistory("up");
    if (historyItem !== null) {
      setInput(historyItem);
    }
  };

  // Navigate to next input in history (down arrow)
  const handleHistoryNext = (): void => {
    const historyItem = navigateHistory("down");
    if (historyItem !== null) {
      setInput(historyItem);
    } else {
      // Reached the end, restore current input
      setInput(currentInputRef.current);
      resetHistoryIndex();
    }
  };

  // Panel-specific key bindings (only active when focused and no modal)
  const panelBindings = createClaudePanelBindings({
    submitMessage: handleSubmit,
    historyPrev: handleHistoryPrev,
    historyNext: handleHistoryNext,
  });

  // Enable panel bindings only when focused and no modal is active
  useKeymap(panelBindings, focused && modalQueue.length === 0);

  // Render message item
  const renderMessage = (message: Message, _index: number): React.ReactNode => {
    return <MessageItem message={message} />;
  };

  return (
    <Box
      flexDirection="column"
      borderStyle={borders.panel}
      borderColor={focused ? colors.focused : colors.unfocused}
      paddingX={1}
      height="100%"
    >
      {/* Header */}
      <Box marginBottom={1}>
        <Text bold color={focused ? colors.focused : colors.muted}>
          Claude Conversation
        </Text>
        {isPlan && (
          <Text bold color="yellow"> [PLAN MODE]</Text>
        )}
      </Box>

      {/* Plan mode info banner */}
      {isPlan && (
        <Box marginBottom={1} borderStyle="round" borderColor="yellow" paddingX={1}>
          <Text color="yellow">
            📋 Claude is planning. Review the plan before approving.
          </Text>
        </Box>
      )}

      {/* Message viewport - constrained to available space */}
      <Box height={maxHeight - 6} overflow="hidden">
        <Viewport
          items={messages}
          renderItem={renderMessage}
          height={Math.max(5, maxHeight - 8)}
          focused={focused && !streaming}
          autoScroll={true}
        />
      </Box>

      {/* Input area */}
      <Box flexDirection="column" marginTop={1}>
        <TextInput
          value={input}
          onChange={setInput}
          placeholder={streaming ? "Waiting for response..." : "Type a message..."}
          disabled={streaming}
          focused={focused}
        />

        {/* Streaming indicator */}
        {streaming && (
          <Box marginTop={1}>
            <Spinner type="dots" />
            <Text color={colors.muted}> Claude is thinking...</Text>
          </Box>
        )}
      </Box>
    </Box>
  );
}

import React from "react";
import { Box, Text, useStdout } from "ink";
import { colors } from "../config/theme.js";

/**
 * Responsive layout component testing terminal resize handling
 * Displays current terminal dimensions and adjusts layout accordingly
 */
export function ResponsiveLayout(): JSX.Element {
  const { stdout } = useStdout();
  const cols = stdout?.columns ?? 80;
  const rows = stdout?.rows ?? 24;

  // Determine layout mode based on terminal size
  const isNarrow = cols < 100;
  const isShort = rows < 20;

  return (
    <Box flexDirection="column" padding={1}>
      <Text bold color={colors.primary}>
        Responsive Layout Test
      </Text>

      <Box marginTop={1}>
        <Text color={colors.secondary}>Terminal Size: </Text>
        <Text bold color={colors.focused}>
          {cols}x{rows}
        </Text>
      </Box>

      <Box marginTop={1} flexDirection="column">
        <Text color={colors.muted}>Layout Mode:</Text>
        {isNarrow && (
          <Text color={colors.warning}>• Narrow mode (&lt; 100 cols)</Text>
        )}
        {isShort && (
          <Text color={colors.warning}>• Short mode (&lt; 20 rows)</Text>
        )}
        {!isNarrow && !isShort && (
          <Text color={colors.success}>• Standard mode</Text>
        )}
      </Box>

      <Box marginTop={1} flexDirection="column">
        <Text color={colors.muted}>
          Resize your terminal to see this update
        </Text>
        <Text dimColor color={colors.muted}>
          (Press Ctrl+C to exit)
        </Text>
      </Box>
    </Box>
  );
}

